(8, 'আর রাহিকুল মাখতুম', 'ar-rahikul-makhtum-90VV', 'book', NULL, 800.00, NULL, 0.001, 'fixed', 501.00, 0, 'আর রাহীকুল মাখতূম: একটি অনবদ্য সীরাত-গ্রন্থ। নবী কারীম সাল্লাল্লাহু আলাইহি ওয়া সাল্লামের সীরাত পর্যালোচনায়, সীরাতের ঘটনামালার সুসংহত ও মনোজ্ঞ উপস্থাপনায় বক্ষ্যমাণ গ্রন্থটি সত্যিই এক নজিরবিহীন রচনা। আল কুরআনুল কারীম, হাদীসে নববী ও বিশুদ্ধ আছার এবং ঐতিহাসিক বর্ণনার নির্যাস বের করে প্রাজ্ঞ লেখক তাঁর এ বইটি সুবিন্যস্ত করেছেন।বইটি নির্ভরযোগ্যতার সর্বোচ্চ মানদণ্ড রক্ষা করে মহানবী সাল্লাল্লাহু আলাইহি ওয়া সাল্লামের পবিত্র সীরাত উপস্থাপন করেছে, যা পাঠকের সামনে উজ্জ্বল করে দেয় সীরাতুল মুস্তাকীমের নিশানাসমগ্র। দেখিয়ে দেয় সীরাতুন্নাবী পাঠের সঠিক পদ্ধতি।', 'আর রাহীকুল মাখতূম: একটি অনবদ্য সীরাত-গ্রন্থ। নবী কারীম সাল্লাল্লাহু আলাইহি ওয়া সাল্লামের সীরাত পর্যালোচনায়, সীরাতের ঘটনামালার সুসংহত ও মনোজ্ঞ উপস্থাপনায় বক্ষ্যমাণ গ্রন্থটি সত্যিই এক নজিরবিহীন রচনা। আল কুরআনুল কারীম, হাদীসে নববী ও বিশুদ্ধ আছার এবং ঐতিহাসিক বর্ণনার নির্যাস বের করে প্রাজ্ঞ লেখক তাঁর এ বইটি সুবিন্যস্ত করেছেন।বইটি নির্ভরযোগ্যতার সর্বোচ্চ মানদণ্ড রক্ষা করে মহানবী সাল্লাল্লাহু আলাইহি ওয়া সাল্লামের পবিত্র সীরাত উপস্থাপন করেছে, যা পাঠকের সামনে উজ্জ্বল করে দেয় সীরাতুল মুস্তাকীমের নিশানাসমগ্র। দেখিয়ে দেয় সীরাতুন্নাবী পাঠের সঠিক পদ্ধতি।', 'products/thumbnails/n2Tzp5nu9xyssvJSMHogcST6gpYEoqzaVsm7pfdN.jpg', NULL, 800, NULL, 'বাংলা', 'বাংলাদেশ', NULL, NULL, NULL, NULL, NULL, 9966, 0, 1, '2026-02-23 12:38:55', '2026-04-03 02:59:32'),
(9, 'শামায়েলে তিরমিজী', 'samayele-tirmijee-gUjk', 'book', NULL, 800.00, NULL, 0.001, 'fixed', 501.00, 0, 'রাসুল সা.-এর দৈনন্দিন কার্যাবলি ও চারিত্রিক গুণাবলির বর্ণনা সম্বলিত হাদিস গ্রন্থ।', 'শামায়েলে তিরমিযী (শামায়েল আন-নববী আল-মুহাম্মদী) একটি বিখ্যাত হাদিস গ্রন্থ, যা প্রণয়ন করেছেন প্রখ্যাত মুহাদ্দিস ইমাম তিরমিযী (রহ.)। এই গ্রন্থে রাসুলুল্লাহ (সা.)-এর চেহারা, চরিত্র, আচার-আচরণ, পোশাক-পরিচ্ছদ, খাদ্যাভ্যাস এবং দৈনন্দিন জীবনের বিবরণ দেওয়া হয়েছে। এটি রাসুলুল্লাহ (সা.)-এর ব্যক্তিত্ব ও জীবনযাপনকে বিস্তারিতভাবে বুঝতে একটি গুরুত্বপূর্ণ গ্রন্থ।\r\nগ্রন্থের মুল বৈশিষ্ঠ! \r\nবিষয়বস্তু: শামায়েলে তিরমিযীতে রাসুলুল্লাহ (সা.)-এর শারীরিক গঠন, আচার-আচরণ, পোশাক, চুল, চলাফেরা, খাবারের পদ্ধতি, ঘুমের ধরন, কথা বলার ধরন ইত্যাদি সম্পর্কে ৩৯টি অধ্যায়ে ৩৯৭টি হাদিস সন্নিবেশিত আছে।\r\nউদ্দেশ্য: এই গ্রন্থের মূল লক্ষ্য হল মুসলমানদের জন্য রাসুলুল্লাহ (সা.)-এর জীবনযাপন ও আচার-আচরণের নিখুঁত উদাহরণ তুলে ধরা। এটি একজন মুসলমানকে রাসুলুল্লাহ (সা.)-এর প্রতি ভালোবাসা ও অনুসরণের জন্য উৎসাহিত করে।\r\nবিশেষত্ব:\r\nসহজ ও সংক্ষিপ্ত উপস্থাপনা।\r\nসাহাবিদের বর্ণিত বিশুদ্ধ ও নির্ভরযোগ্য হাদিস সংকলন।\r\nরাসুলুল্লাহ (সা.)-এর জীবনের নানা দিকের গভীর বিশ্লেষণ।\r\nবিস্তৃত প্রভাব: এই গ্রন্থ ইসলামি সাহিত্য ও সংস্কৃতিতে গভীর প্রভাব ফেলেছে। মুসলিম মনীষীরা এই গ্রন্থ অধ্যয়নের মাধ্যমে রাসুলুল্লাহ (সা.)-এর চরিত্র ও আচরণ অনুকরণের জন্য উদ্বুদ্ধ হয়েছেন।\r\nশামায়েলে তিরমিযী এমন একটি গ্রন্থ, যা রাসুলুল্লাহ (সা.)-এর প্রতি গভীর ভালোবাসা ও অনুগত্যের শিক্ষা দেয়। এটি আজও মুসলিম বিশ্বের মধ্যে ব্যাপকভাবে পঠিত ও সম্মানিত।\r\nনাম :শামায়েলে তিরমিযী\r\nলেখক: হাফেজে হাদিস মুহাম্মাদ ইবনে ঈসা আত-তিরমি্যী রঃ\r\nঅনুবাদক: মাওলানা মুখলিস বিন সুলতা', 'products/thumbnails/TJanEj6Uo3Y6cu9kZM2eMyQyBpzkfXBOEG9XlBUy.jpg', NULL, 800, NULL, 'Bangla', 'BD', NULL, NULL, NULL, NULL, NULL, 9990, 0, 1, '2026-02-23 12:51:10', '2026-03-11 04:32:45'),
(10, 'প্যারাডক্সিক্যাল সাজিদ', 'pzaradksikzal-sajid-Z37J', 'book', NULL, 225.00, NULL, 0.001, NULL, NULL, 0, NULL, NULL, 'products/thumbnails/veDGMmlwwxon1c7mCUzxEJffJIhuU4w0Ve4qUSoj.jpg', NULL, 168, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1000, 0, 1, '2026-02-23 12:56:38', '2026-02-23 12:56:38'),
(11, 'রিয়াদুস সলেহীন ১-৪ খন্ড (বাংলা-আরবি)', 'riyadus-sleheen-1-4-khnd-bangla-arbi-p989', 'book', NULL, 3200.00, NULL, 0.001, 'fixed', 2301.00, 0, NULL, 'সম্পূর্ণ সংকলনের বৈশিষ্ট্য ও বিশেষত্ব\r\nসহিহ ও বিশুদ্ধ হাদিসের সংকলন\r\nসরাসরি নিকটস্থ সূত্র থেকে যাচাই করা হাদিসসমূহ—ঈমান ও আমলের ক্ষেত্রে অটল ভিত্তি গড়ে তোলে।\r\n\r\n৪ খণ্ডে পূর্ণাঙ্গ থিমভিত্তিক বিন্যাস\r\nপ্রতি খণ্ডে আলাদাভাবে সাজানো হাদিস:\r\n\r\nদুনিয়ার প্রতি নিরাসক্তি, জাহদের গুরুত্ব\r\n\r\nআত্মশুদ্ধি ও চরিত্রগঠন\r\n\r\nজাহেরি–বাতেনি আদব ও কলবের পবিত্রতা\r\n\r\nতত্ত্বজ্ঞান, পরকালের মুক্তি ও নাজাতের পথপ্রদর্শন\r\n\r\nব্যাপক টীকা ও অনুবাদ\r\nঅনুবাদক–সম্পাদকদের সহজবোধ্য বাংলা টীকা, ইসলামি পরিভাষার পরিচিতি ও প্রসঙ্গভিত্তিক ব্যাখ্যা।\r\n\r\nআত্মসংশোধন ও আদর্শিক অনুপ্রেরণা\r\nপ্রতিটি হাদিসে রয়েছে আধ্যাত্মিক ও সামাজিক জীবনের বাস্তব প্রয়োগ—নিজেকেও খুঁজে পাবেন, জীবনের দিশাও।\r\n\r\nউচ্চমানের হার্ডকভার\r\nদীর্ঘস্থায়ী সংরক্ষণ নিশ্চিত করার জন্য শক্তিশালী বাঁধাই, পাঠের অভিজ্ঞতা আরও মাধুর্যময়।\r\n\r\nকেন এই সংকলন আপনার সংগ্রহের অংশ?\r\nবিশ্বস্ত ও নির্ভরযোগ্য: সহিহ হাদিসের বিশ্ববিখ্যাত উৎস, মুসলিম উম্মাহর অমুল্য সম্পদ।\r\n\r\nব্যক্তিগত উন্নতি: দিনরাত পাঠ ও আমলের মাধ্যমে আপনি পাবেন অন্তরিক শান্তি ও আত্মিক মানসিকতা।\r\n\r\nপরিবারের জন্য আদর্শ: ঘরের সবাই—বয়ঃ যাত্রা নির্বিশেষে—একসঙ্গে পাঠ করতে পারে, গঠনমূলক আলোচনার মাধ্যমে সম্পর্ক আরও দৃঢ় হয়।\r\n\r\nঅধ্যয়ন ও শিক্ষা: ছাত্র থেকে পণ্ডিত—সবারই কাজে লাগবে; মাদ্রাসা, মসজিদ, পরিবারের পাঠচক্রে অপরিহার্য।', 'products/thumbnails/lf6yZp05CAjsesvAePg9uoFzLDSDuw4cwvyl0Tyi.jpg', NULL, 1932, NULL, 'Bangla', 'BD', NULL, NULL, NULL, NULL, NULL, 48, 0, 1, '2026-02-23 13:01:07', '2026-03-30 15:13:36'),
(12, 'আত্মশুদ্ধি ও তাসাউফ', 'atmsuddhi-oo-tasauf-Cqp9', 'book', NULL, 500.00, NULL, 0.001, 'fixed', 301.00, 0, NULL, 'আত্মশুদ্ধি ও তাসাউফ , মুমিন জীবনের সাথে সংশ্লিষ্ট গুরুত্বপূর্ণ একটি অনুষঙ্গ। আত্মিক উন্নতি ছাড়া মুমিন নিজেকে নফসের ধোঁকা থেকে, শয়তানের কবজা থেকে হেফাজত রাখতে পারে না। মুমিনের আত্মিক উন্নতির এ মাধ্যমই হলো ‘আত্মশুদ্ধি ও তাসাউফ’। . নফসের বিরুদ্ধে লড়াই করে জিততে পারলেই একজন মানুষ মুমিন হিসেবে নিজেকে রবের সামনে উপস্থাপন করতে পারবে, রবের পক্ষ থেকে মুক্তির আশা রাখতে পারবে। অন্যথায় শয়তান এবং নফসের আধিপত্য তাকে জাহান্নামের গর্তে নিক্ষেপ করবে। চিরসুখ থেকে বিমুখ করে দুর্দশাগ্রস্ত করবে। . অন্তরের সেসব ব্যাধি এবং তার চিকিৎসা নিয়েই রচিত এ বইটি। শাইখুল ইসলাম মুফতি মুহাম্মদ তাকি উসমানি সাহেব দামাত বারকাতুহুম রচিত এ গ্রন্থটি মানুষের দিলের সেসব রোগ এবং ব্যাধি দূরের প্রক্রিয়া ও মাধ্যম জানাবে। বইটির পাঠ মানস মনে শুদ্ধির ঝড় তুলুক এবং এবং শয়তানের কুমন্ত্রণা, নফসের গোলামি থেকে হেফাজত করুক।', 'products/thumbnails/sn1GLnVxhWMrTeJalcykw7UHVJrPUPLVjfDe12nl.jpg', NULL, 344, NULL, 'Bangla', 'BD', NULL, NULL, NULL, NULL, NULL, 1000, 0, 1, '2026-02-23 13:06:36', '2026-02-23 13:06:36'),
(13, 'আত তিব্বুন নববী', 'at-tibbun-nbbee-ANEp', 'book', NULL, 950.00, NULL, 0.001, 'percent', 70.00, 0, NULL, '‘আত তিব্বুন নববী’ রাসূলুল্লাহ ﷺ এর শিক্ষা ও দিকনির্দেশনার আলোকে শারীরিক ও আত্মিক রোগের চিকিৎসা পদ্ধতির অনন্য সংকলন। এতে নবীজির চিকিৎসা পদ্ধতি, খাদ্যাভ্যাস, স্বাস্থ্য রক্ষণাবেক্ষণ ও রুহানী শিফার উপায় বিস্তারিতভাবে আলোচিত হয়েছে।', 'products/thumbnails/z6lTfmaHfoPyueV5QzS4vjxhv7mXZHkfuOyEi6xZ.jpg', NULL, NULL, NULL, 'বাঙলা', 'Bangladesh', NULL, NULL, NULL, NULL, NULL, 98, 0, 1, '2026-02-23 13:10:33', '2026-03-05 12:27:06'),
(14, 'হিসনুল মুসলিম (পেপারব্যাক)', 'hisnul-muslim-peparbzak-hwvi', 'book', NULL, 80.00, NULL, 0.001, 'fixed', 25.00, 0, NULL, 'কুরআন-সুন্নাহ থেকে সংগৃহীত যিকর ও দো‘আ সংক্রান্ত এটি একটি বিশুদ্ধ ও নির্ভরযোগ্য সংকলনের অনুবাদ। গ্রন্থে সন্নিবেশিত প্রতিটি যিকর ও দো‘আর সঙ্গে রেফারেন্স যুক্ত করা হয়েছে। এতে যিকর ও দো‘আর পাশাপাশি কুরআন-সুন্নাহর আলোকে ‘ঝাড়-ফুঁকের মাধ্যমে চিকিৎসা’ বিষয়ক একটি অধ্যায় যুক্ত করা হয়েছে। সাঈদ ইবনু আলী আল-কাহতানী কুরআন-সুন্নাহ থেকে সংগৃহীত যিকর ও দো‘আ সংক্রান্ত এটি একটি বিশুদ্ধ ও নির্ভরযোগ্য সংকলনের অনুবাদ। গ্রন্থে সন্নিবেশিত প্রতিটি যিকর ও দো‘আর সঙ্গে রেফারেন্স যুক্ত করা হয়েছে। এতে যিকর ও দো‘আর পাশাপাশি কুরআন-সুন্নাহর আলোকে ‘ঝাড়-ফুঁকের মাধ্যমে চিকিৎসা’ বিষয়ক একটি অধ্যায় যুক্ত করা হয়েছে। আল্লামা নাসীরুদ্দিন আলবাণীর তাহক্বীক সহ আরো যে সমস্ত মুহাদ্দিসদের তাহক্বীক রয়েছে তারা হলেন, শায়খ বিন বায। ইমাম তিরমিযি। ইমাম আয যাহাবী। ইমাম হাকিম সহ প্রমূখ।', 'products/thumbnails/cypoDHO88mqgu49vjUvC0Jyk46unEjGggc0XtFYf.jpg', NULL, 170, NULL, 'Bangla', 'BD', NULL, NULL, NULL, NULL, NULL, 1000, 0, 1, '2026-02-23 13:22:36', '2026-02-23 13:30:13'),
(15, '৫ টি বেস্টসেলার বই ( আর রাহিকুল, মাখতুম, আত্মশুদ্ধি ও তাসাউফ, আত তিব্বুন নববী, হিসনুল মুসলিম)', '5-ti-bestselar-bi-ar-rahikul-makhtum-atmsuddhi-oo-tasauf-at-tibbun-nbbee-hisnul-muslim-ARc8', 'book', NULL, 3000.00, NULL, 0.001, 'fixed', 2001.00, 1, NULL, '1️⃣ হিসনুল মুসলিম\r\nকুরআন ও সহীহ হাদীস থেকে সংগৃহীত যিকর, দো‘আ ও রুকইয়ার নির্ভরযোগ্য সংকলন।\r\n✔ প্রতিটি যিকর ও দো‘আর সাথে রেফারেন্স সংযুক্ত।\r\n✔ নিত্যদিনের আমলের জন্য অত্যন্ত গুরুত্বপূর্ণ একটি বই।\r\n\r\n2️⃣ শামায়েলে তিরমিজি\r\nনবীজী (সা.)-এর দৈহিক গঠন, চাল-চলন, পোশাক-পরিচ্ছদ, ও ব্যবহারবিধি নিয়ে রচিত হাদীসসংকলন।\r\n🕋 সীরাতভিত্তিক যেকোনো গবেষণায় এই গ্রন্থ অপরিহার্য দলিল।\r\n📘 হাদীসের আলোকে জীবনের শিক্ষা।\r\n\r\n3️⃣ তাসাওউফ ও আত্মশুদ্ধি\r\nআত্মাকে পরিশুদ্ধ করার জন্য আলোকিত পথনির্দেশ।\r\n🌿 হৃদয়ের গভীরে পৌঁছানোর মতো শব্দে গঠিত।\r\n🕌 যারা আত্মিক উন্নতির পথে চলতে চান, তাদের জন্য সহায়ক।\r\n\r\n4️⃣ আর রাহিকুল মাখতুম\r\nবিশ্ববিখ্যাত সীরাতগ্রন্থ যা ১১৮২টি বইয়ের প্রতিযোগিতায় ১ম স্থান অর্জন করে।\r\n📖 রাসূলুল্লাহ ﷺ-এর জীবন, সংগ্রাম, দাওয়াহ, ও আদর্শের পূর্ণ বিবরণ।\r\n🔥 নবীজীর জীবনী জানতে আগ্রহীদের জন্য সেরা বই।\r\n\r\n5️⃣ আত তিব্বুন নববী\r\nরাসূলুল্লাহ ﷺ প্রদর্শিত চিকিৎসা পদ্ধতির অসাধারণ সংকলন।\r\n🍯 মধু, কালোজিরা, খেজুর, অলিভ, হারবাল চিকিৎসা—সবকিছুই একটি বইতে।\r\n✅ সুন্নাহভিত্তিক স্বাস্থ্যচর্চা জানতে চাইলে এটি অবশ্যপাঠ্য।\r\n\r\n👉 আজই সংগ্রহ করুন এবং ইসলামী জ্ঞানে সমৃদ্ধ হোন!', 'products/thumbnails/MZKkVMXJHJvq9S2MNosMIKPGmSdeDBaaAKp0cefd.jpg', NULL, NULL, NULL, 'Bangla=Arabic', 'Bangladesh', NULL, NULL, NULL, NULL, NULL, 9997, 0, 1, '2026-02-23 13:32:20', '2026-02-23 17:20:00'),
(16, 'কালার কোডেড সহজ কুরআন মাজিদ ও আর রাহিকুল মাখতুম কম্বো (সাথে আরও ১৫ টি গিফট)', 'kalar-koded-shj-kuran-majid-oo-ar-rahikul-makhtum-Qyzs', 'book', NULL, 3050.00, NULL, 0.001, 'fixed', 1860.00, 0, 'সহিহ ও শুদ্ধভাবে কুরআন তিলাওয়াত শেখার এক অনন্য সমাধান— \"কালার কোডেড সহজ ক্বারীয়ানা উচ্চারণ কুরআন মাজীদ\"। ৮টি কালার কোডেড তাজবীদ, স্পষ্ট বড় হরফ, চোখের প্রশান্তিদায়ক নন-রিফ্লেক্টিভ পেপার এবং কিউআর কোড স্ক্যান করে নিজে নিজে তাজবীদ শেখার দারুণ সব ফিচার নিয়ে সাজানো হয়েছে এই কুরআনটি। আরবী না জানলেও বাংলায় ক্বারীয়ানা উচ্চারণ দেখে আজই শুরু করুন আপনার শুদ্ধ তিলাওয়াতের যাত্রা।', '🔥 বিশেষ ইসলামিক বই প্যাকেজ – সীমিত সময়ের জন্য! \r\n📘 কালার কোডেড সহজ কুরআন মাজিদ\r\n📗 আর রাহিকুল মাখতুম\r\n📙 হিসনুল মুসলিম\r\n📕 ৬টি সাহাবীদের জীবনী বই\r\n\r\n🎁 সাথে পাচ্ছেন একদম ফ্রি ৫টি স্পেশাল গিফট—\r\n✔ উডেন মোবাইল স্ট্যান্ড\r\n✔ তুর্কি টুপি\r\n✔ মিসওয়াক\r\n✔ আতর\r\n✔ তজবি\r\n\r\n\r\n\"আপনি শুধু কুরআন তিলাওয়াত শুরু করুন, শুদ্ধ করে তিলাওয়াতের দায়িত্ব আমাদের!\"\r\n\r\nকুরআন মজিদ সহিহ ও শুদ্ধভাবে পড়া প্রতিটি মুসলিমের একান্ত কর্তব্য। যারা তাজবীদসহ কুরআন পড়তে গিয়ে সমস্যার সম্মুখীন হন, তাদের জন্য আমরা নিয়ে এসেছি কালার কোডেড সহজ ক্বারীয়ানা উচ্চারণ কুরআন মাজীদ। ইনশাআল্লাহ্‌, আপনার কুরআন তিলাওয়াতের সকল সমস্যার সমাধান পাবেন এখানেই।\r\n\r\nকেন এই কুরআন মাজীদটি আপনার জন্য সেরা?\r\n\r\n📱 কিউআর কোড (QR Code) সুবিধা: কোরআন পড়ার নিয়ম-কানুন নিজে থেকে শেখার জন্য এতে দেওয়া আছে বিশেষ কিউআর কোড। স্মার্টফোন দিয়ে স্ক্যান করেই নিয়মগুলো অডিওতে শুনে নিজে নিজেই শিখতে পারবেন।\r\n\r\n🗣️ বাংলায় ক্বারীয়ানা উচ্চারণ: আরবির পাশাপাশি বাংলাতেও তাজবীদের নিয়ম দেওয়া হয়েছে। যেমন: (১) লেখা থাকলে এক আলিফ, (২) থাকলে দুই আলিফ, (৩) থাকলে তিন আলিফ এবং (৪) লেখা থাকলে চার আলিফ টানতে হবে। এর সাথে আরবি উচ্চারণের বিশেষ সাংকেতিক চিহ্ন তো থাকছেই!\r\n\r\n🎨 ৮টি কালার কোডেড তাজবীদ: তাজবীদের নিয়মগুলো সহজে মনে রাখার জন্য ৮টি ভিন্ন রঙের ব্যবহার করা হয়েছে, যা দেখে আপনি সহজেই বুঝতে পারবেন কোথায় গুন্নাহ করতে হবে আর কোথায় টানতে হবে।\r\n\r\n📖 উন্নতমানের পেপার: এমন উন্নতমানের কাগজ ব্যবহার করা হয়েছে যা আলো রিফ্লেক্ট করে না। ফলে দীর্ঘক্ষণ তিলাওয়াত করলেও চোখে কোনো চাপ বা সমস্যা হয় না।\r\n\r\n🔠 বড় ও স্পষ্ট হরফ: বয়স্ক থেকে শুরু করে যে কারো পড়ার সুবিধার্থে বড় বড় হরফ ব্যবহার করা হয়েছে।\r\n\r\n🔖 সহজ সাংকেতিক চিহ্ন: তাজবীদসহ তিলাওয়াত আরো সহজ করতে প্রতিটি পৃষ্ঠায় রয়েছে প্রয়োজনীয় সাংকেতিক চিহ্ন।', 'products/thumbnails/72WvRVDtWwJeZR3MrwJeX7I3YxjFwpFWcXRyBEep.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 964, 0, 1, '2026-02-23 14:23:51', '2026-04-01 06:45:40'),
(17, 'আর রাহীকুল মাখতূম এবং আত্মশুদ্ধি ও তাসাওউফ', 'ar-raheekul-makhtuum-ebng-atmsuddhi-oo-tasaoouf-xD60', 'book', 'আর রাহীকুল মাখতূম এবং আত্মশুদ্ধি ও তাসাওউফ', 1300.00, 220.00, 0.001, 'percent', 61.61, 0, '1️⃣ আর রাহীকুল মাখতূম (৮০০ পৃষ্ঠা)\r\nমহানবী হযরত মুহাম্মদ ﷺ-এর সীরাত বা জীবনী নিয়ে রচিত বিশ্ববিখ্যাত গ্রন্থ। এখানে নবীজীর শৈশব থেকে শুরু করে দাওয়াতি কার্যক্রম, সংগ্রাম, বিজয় ও ইসলামের প্রচার পর্যন্ত পূর্ণাঙ্গ জীবনচিত্র বিশুদ্ধ ঐতিহাসিক ভিত্তিতে উপস্থাপন করা হয়েছে। এটি একজন মুসলিমের জন্য নবীজীর জীবনধারা জানার অপরিহার্য সহায়ক।\r\n\r\n2️⃣ তাসাওউফ ও আত্মশুদ্ধি (৩৪৪ পৃষ্ঠা)\r\nমুফতি তাকি উসমানীর রচিত আত্মশুদ্ধি ও আধ্যাত্মিকতার একটি অনন্য গ্রন্থ। এতে নফসের রোগ, আধ্যাত্মিক ব্যাধি এবং তার থেকে মুক্তির সঠিক পদ্ধতি বর্ণিত হয়েছে। বইটি আত্মিক উন্নয়ন, অন্তরের শান্তি এবং আল্লাহর নৈকট্য লাভে সহায়ক।\r\n\r\n✨ এই প্যাকেজ একজন মুমিনকে সীরাতের মাধ্যমে দুনিয়াবি ও আখিরাতের সফলতার দিশা দেখায় এবং আত্মশুদ্ধির মাধ্যমে অন্তরের জগতকে আলোকিত করে।', '1️⃣ আর রাহীকুল মাখতূম (৮০০ পৃষ্ঠা)\r\nমহানবী হযরত মুহাম্মদ ﷺ-এর সীরাত বা জীবনী নিয়ে রচিত বিশ্ববিখ্যাত গ্রন্থ। এখানে নবীজীর শৈশব থেকে শুরু করে দাওয়াতি কার্যক্রম, সংগ্রাম, বিজয় ও ইসলামের প্রচার পর্যন্ত পূর্ণাঙ্গ জীবনচিত্র বিশুদ্ধ ঐতিহাসিক ভিত্তিতে উপস্থাপন করা হয়েছে। এটি একজন মুসলিমের জন্য নবীজীর জীবনধারা জানার অপরিহার্য সহায়ক।\r\n\r\n2️⃣ তাসাওউফ ও আত্মশুদ্ধি (৩৪৪ পৃষ্ঠা)\r\nমুফতি তাকি উসমানীর রচিত আত্মশুদ্ধি ও আধ্যাত্মিকতার একটি অনন্য গ্রন্থ। এতে নফসের রোগ, আধ্যাত্মিক ব্যাধি এবং তার থেকে মুক্তির সঠিক পদ্ধতি বর্ণিত হয়েছে। বইটি আত্মিক উন্নয়ন, অন্তরের শান্তি এবং আল্লাহর নৈকট্য লাভে সহায়ক।\r\n\r\n✨ এই প্যাকেজ একজন মুমিনকে সীরাতের মাধ্যমে দুনিয়াবি ও আখিরাতের সফলতার দিশা দেখায় এবং আত্মশুদ্ধির মাধ্যমে অন্তরের জগতকে আলোকিত করে।', 'products/thumbnails/6ZfeiJOU32FewIon8oyhFuNwi6LYf96EW6dw6fos.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 99, 0, 1, '2026-03-10 02:13:21', '2026-03-12 09:40:04'),
(18, 'আল কুরআন ও আধুনিক বিজ্ঞান - ৩টি বইয়ের প্যাকেজ (হার্ডকভার)', 'al-kuran-oo-adhunik-bijngan-3ti-byer-pzakej-hardkvar-90kL', 'book', 'আল কুরআন ও আধুনিক বিজ্ঞান - ৩টি বইয়ের প্যাকেজ (হার্ডকভার)', 850.00, 280.00, 0.001, 'fixed', 301.00, 0, 'কুর\'আনের অন্যতম বৈশিষ্ট্য হলো এটি বিজ্ঞানের কোন গ্রন্থ নয়। কিন্তু এটি বিজ্ঞানময়। আল-কুরআনের অসংখ্য আয়াতে জ্ঞান-বিজ্ঞানের সর্বাধুনিক তথ্য ও তত্ত্বগুলো যেন স্বমহিমায় উজ্জ্বল হয়ে আছে।\r\n\r\nকুরআনের সঙ্গে জ্ঞান বিজ্ঞানের বিভিন্ন শাখার আধুনিক তত্ত্বগুলোর সামঞ্জস্য আলোচনা করে লেখা অন্যতম বই হলো \'আল কুরআন ও আধুনিক বিজ্ঞান\' \'বাইবেল কোরআন ও বিজ্ঞান এবং \'গানিতিক রহস্যময় কুরআন\'\r\n\r\nবইগুলো পড়ে পাঠক অবাক বিস্ময়ে লক্ষ্য করবেন আধুনিক বিজ্ঞানের অনেক নির্দেশনা ঐশীগ্রন্থ আল কুরআনে বহুপূর্বেই দেয়া হয়েছে,লেখকগন তাদের লিখনীতে যে সব বৈজ্ঞানিক ব্যখ্যা আর ধর্মীয় বিষয় তুলে এনেছেন তা সত্যিই অবাক করার মত। সব মিলিয়ে দারুণ উপভোগ্য তিনটি বই।\r\nবইগুলো পড়লে মনে হবে আল কুরআন যে সবচেয়ে বড় বিজ্ঞান তা বইগুলো না পড়লে অজানা থেকে যেতো।\r\n\r\n1.আল কুরআন ও আধুনিক বিজ্ঞান\r\nলেখক: ডা. জাকির নায়েক\r\n2. বাইবেল কোরআন ও বিজ্ঞান\r\nলেখক: ডা. মরিস বুকাইলি\r\n3.গানিতিক রহস্যময় কুরআন\r\nলেখক: আহমেদ দিদাত', 'কুর\'আনের অন্যতম বৈশিষ্ট্য হলো এটি বিজ্ঞানের কোন গ্রন্থ নয়। কিন্তু এটি বিজ্ঞানময়। আল-কুরআনের অসংখ্য আয়াতে জ্ঞান-বিজ্ঞানের সর্বাধুনিক তথ্য ও তত্ত্বগুলো যেন স্বমহিমায় উজ্জ্বল হয়ে আছে।\r\n\r\nকুরআনের সঙ্গে জ্ঞান বিজ্ঞানের বিভিন্ন শাখার আধুনিক তত্ত্বগুলোর সামঞ্জস্য আলোচনা করে লেখা অন্যতম বই হলো \'আল কুরআন ও আধুনিক বিজ্ঞান\' \'বাইবেল কোরআন ও বিজ্ঞান এবং \'গানিতিক রহস্যময় কুরআন\'\r\n\r\nবইগুলো পড়ে পাঠক অবাক বিস্ময়ে লক্ষ্য করবেন আধুনিক বিজ্ঞানের অনেক নির্দেশনা ঐশীগ্রন্থ আল কুরআনে বহুপূর্বেই দেয়া হয়েছে,লেখকগন তাদের লিখনীতে যে সব বৈজ্ঞানিক ব্যখ্যা আর ধর্মীয় বিষয় তুলে এনেছেন তা সত্যিই অবাক করার মত। সব মিলিয়ে দারুণ উপভোগ্য তিনটি বই।\r\nবইগুলো পড়লে মনে হবে আল কুরআন যে সবচেয়ে বড় বিজ্ঞান তা বইগুলো না পড়লে অজানা থেকে যেতো।\r\n\r\n1.আল কুরআন ও আধুনিক বিজ্ঞান\r\nলেখক: ডা. জাকির নায়েক\r\n2. বাইবেল কোরআন ও বিজ্ঞান\r\nলেখক: ডা. মরিস বুকাইলি\r\n3.গানিতিক রহস্যময় কুরআন\r\nলেখক: আহমেদ দিদাত', 'products/thumbnails/xaogcItziN0sam5K7fNA9lm1Fx2m9fq6FlwQUIkN.jpg', NULL, 525, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 927, 0, 1, '2026-03-10 02:20:06', '2026-04-01 22:21:29'),
(19, 'আন্তর্জাতিক ইসলামিক স্কলারদের সাজেস্টকৃত বেস্ট সেলিং ৫টি বই', 'antrjatik-islamik-sklarder-sajestkrrit-best-seling-5ti-bi-73or', 'book', 'আন্তর্জাতিক ইসলামিক স্কলারদের সাজেস্টকৃত বেস্ট সেলিং ৫টি বই', 2343.00, 600.00, 0.001, 'percent', 58.00, 0, 'একটি দ্যুতিময় সীরাত–গ্রন্থ যা নবীর জীবনের প্রতিটি অধ্যায়কে জীবন্ত করে তোলে। প্রাক-ইসলামিক আরবের কঠিন বাস্তবতার চিত্র, নবুওয়াত লাভের আবেগ, হৃদয়স্পর্শী হিজরাতের গল্প, বিখ্যাত যুদ্ধে সাহসিকতার নজির—সবই এমন ভাষায় তুলে ধরা হয়েছে যে, প্রথম পাতা থেকে শেষ পর্যন্ত মন ছুঁয়ে যায়। আধুনিক গবেষণা ও পুরোনো ভারত–আরব সূত্রের আলোকে সাজানো, এটি আপনার বিশ্বাসকে করবে শক্তিশালী এবং জীবনের প্রতি দৃষ্টিভঙ্গি পাল্টে দেবে। যে মানুষটি নবীর আদর্শিক শিক্ষা থেকেই আত্মস্ফূর্তি খুঁজছেন, তার সংগ্রহে এটি একটি অপরিহার্য সম্পদ।\r\n\r\n১. আর রাহীকুল মাখতুম\r\n\r\nলেখক: আল্লামা সফিউর রহমান মুবারকপুরী (রহ.)\r\n\r\nঅনুবাদক: মাসরূর সামী\r\n\r\nপ্রকাশনী: মাকতাবায়ে যাকারিয়া\r\n\r\nপৃষ্ঠা: ৮০০ | হার্ডকভার | বাংলা\r\n\r\n\r\n\r\n\r\n\r\n২. প্যারাডক্সিক্যাল সাজিদ\r\n\r\nলেখক: আরিফ আজাদ\r\n\r\nপ্রকাশনী: গার্ডিয়ান পাবলিকেশনস\r\n\r\nপৃষ্ঠা: ১৬৮ | হার্ডকভার | বাংলা\r\n\r\nবিস্তারিত বর্ণনা:\r\nযখন যুক্তি আর গল্পের মিশেলে অন্ধবিশ্বাসের অজানা কারন উন্মোচিত হয়, তখন বোঝা যায় ‘প্যারাডক্সিক্যাল সাজিদ’-এর ম্যাজিক। সাজিদ তার জীবনের অভিজ্ঞতার আলোকে ইসলামবিরোধী অভিযোগের লজিক্যাল পর্যালোচনা করে, মিথ্যা প্রচারণার সামনে থমকে দাঁড়ানোর শক্তি যোগায়। একাধিক আকর্ষণীয় দেনদরবার ও মর্মস্পর্শী কেস স্টাডির মাধ্যমে, বইটি পাঠককে নিজেদের প্রশ্ন ও সন্দেহের স্বচ্ছতা খুঁজে পেতে সাহায্য করে। যারা নিজেদের জ্ঞান পরিসর জোরদার করে আত্মবিশ্বাসী যুক্তিবাদী হতে চান, তাদের জন্য এটি আদর্শ।\r\n\r\n৩. আত্মশুদ্ধি ও তাসাওউফ\r\n\r\nলেখক: শাইখুল ইসলাম মুফতী মুহাম্মাদ তাকী উসমানী (রহ.)\r\n\r\nঅনুবাদক: মাওলানা মুহাম্মাদ জালালুদ্দিন\r\n\r\nপ্রকাশনী: মাকতাবায়ে যাকারিয়া\r\n\r\nপৃষ্ঠা: ৩৮৪ | হার্ডকভার | বাংলা\r\n\r\nবিস্তারিত বর্ণনা:\r\nআত্মিক রোগ নিরাময়, ওয়াসওয়াসার মোকাবেলা, নফস নিয়ন্ত্রণ—এই গ্রন্থে সবকিছুই অন্তর্মুখী ও বহির্মুখী দুই দিক থেকেই আলোচিত। ‘তাযকিয়া’ পদ্ধতির জ্ঞানভাণ্ডার, ইহকাল ও পরকালের সফলতার মন্ত্র, এবং সহজ অনুশীলন–টিপস দিয়ে, শাইখুল ইসলামের ভাষায় লেখা এই বই আপনার মনের নড়বড়ে ভাবকে স্থিতিশীল করে তুলবে। প্রতিদিনের চাপ, ঘাত পেতে ভয়, আত্মজ্ঞানের অভাব—এসব কাটিয়ে উঠতে এটি হবে আপনার অমূল্য সঙ্গী।\r\n\r\n৪. শামায়েলে তিরমিজি\r\n\r\nলেখক: ইমাম তিরমিজি (রহ.)\r\n\r\nপ্রকাশনী: মাকতাবায়ে যাকারিয়া\r\n\r\nপৃষ্ঠা: ৮০০ | হার্ডকভার | বাংলা\r\n\r\nবিস্তারিত বর্ণনা:\r\nনবী করীমের দৈহিক অবয়ব, পোশাক-আচরণ, চারিত্রিক বৈশিষ্ট্য ও নৈতিক গুণাবলী সম্পর্কে ৫৬টি অধ্যায়ে সাজানো ৪৫৬টি হাদিস—‘শামায়েলে তিরমিজি’ হাঁড়ভাঙা গবেষণা ও সহজপাঠ্য অনুবাদে। বর্তমান যুগের ধর্মপ্রাণ মানুষদের জন্য এটি হবে সেরা চিত্রপট: নবীর আদর্শ অনুসরণের অনুপ্রেরণা, আত্মসংযমের শিক্ষা ও মানবিক দৃষ্টিভঙ্গি গড়ে তোলার অসামান্য হাতিয়ার।\r\n\r\n৫. হিসনুল মুসলিম\r\n\r\nলেখক: সৈয়দ বিন আলী আল-কাহতানী (মূল রচয়িতা)\r\n\r\nসম্পাদনা ও অনুবাদ: মাকতাবায়ে যাকারিয়া\r\n\r\nপৃষ্ঠা: ১০৫৬ | হার্ডকভার | বাংলা\r\n\r\nবিস্তারিত বর্ণনা:\r\nসকালে ‘বিসমিল্লাহ’ থেকে রাতের শেষ দোয়া পর্যন্ত—প্রতিটি মুহূর্ত আল্লাহর সান্নিধ্য অনুভব করুন ১০৫৬ পাতার এই অমুল্য দোয়া-সংকলনের মাধ্যমে। হৃদয়কে প্রশান্তি, মনকে স্থিতশীলতা এবং দেহকে মানসিক শক্তি প্রদানে ‘হিসনুল মুসলিম’ আপনার প্রতিদিনের ধারাবাহিক আমল। সময়ের অনিশ্চয়তার মাঝে আনুন অটল বিশ্বাসের প্রাচীর—এটি হবে প্রতিটি পরিবারের সৌধপত্র।', 'একটি দ্যুতিময় সীরাত–গ্রন্থ যা নবীর জীবনের প্রতিটি অধ্যায়কে জীবন্ত করে তোলে। প্রাক-ইসলামিক আরবের কঠিন বাস্তবতার চিত্র, নবুওয়াত লাভের আবেগ, হৃদয়স্পর্শী হিজরাতের গল্প, বিখ্যাত যুদ্ধে সাহসিকতার নজির—সবই এমন ভাষায় তুলে ধরা হয়েছে যে, প্রথম পাতা থেকে শেষ পর্যন্ত মন ছুঁয়ে যায়। আধুনিক গবেষণা ও পুরোনো ভারত–আরব সূত্রের আলোকে সাজানো, এটি আপনার বিশ্বাসকে করবে শক্তিশালী এবং জীবনের প্রতি দৃষ্টিভঙ্গি পাল্টে দেবে। যে মানুষটি নবীর আদর্শিক শিক্ষা থেকেই আত্মস্ফূর্তি খুঁজছেন, তার সংগ্রহে এটি একটি অপরিহার্য সম্পদ।\r\n\r\n১. আর রাহীকুল মাখতুম\r\n\r\nলেখক: আল্লামা সফিউর রহমান মুবারকপুরী (রহ.)\r\n\r\nঅনুবাদক: মাসরূর সামী\r\n\r\nপ্রকাশনী: মাকতাবায়ে যাকারিয়া\r\n\r\nপৃষ্ঠা: ৮০০ | হার্ডকভার | বাংলা\r\n\r\n\r\n\r\n\r\n\r\n২. প্যারাডক্সিক্যাল সাজিদ\r\n\r\nলেখক: আরিফ আজাদ\r\n\r\nপ্রকাশনী: গার্ডিয়ান পাবলিকেশনস\r\n\r\nপৃষ্ঠা: ১৬৮ | হার্ডকভার | বাংলা\r\n\r\nবিস্তারিত বর্ণনা:\r\nযখন যুক্তি আর গল্পের মিশেলে অন্ধবিশ্বাসের অজানা কারন উন্মোচিত হয়, তখন বোঝা যায় ‘প্যারাডক্সিক্যাল সাজিদ’-এর ম্যাজিক। সাজিদ তার জীবনের অভিজ্ঞতার আলোকে ইসলামবিরোধী অভিযোগের লজিক্যাল পর্যালোচনা করে, মিথ্যা প্রচারণার সামনে থমকে দাঁড়ানোর শক্তি যোগায়। একাধিক আকর্ষণীয় দেনদরবার ও মর্মস্পর্শী কেস স্টাডির মাধ্যমে, বইটি পাঠককে নিজেদের প্রশ্ন ও সন্দেহের স্বচ্ছতা খুঁজে পেতে সাহায্য করে। যারা নিজেদের জ্ঞান পরিসর জোরদার করে আত্মবিশ্বাসী যুক্তিবাদী হতে চান, তাদের জন্য এটি আদর্শ।\r\n\r\n৩. আত্মশুদ্ধি ও তাসাওউফ\r\n\r\nলেখক: শাইখুল ইসলাম মুফতী মুহাম্মাদ তাকী উসমানী (রহ.)\r\n\r\nঅনুবাদক: মাওলানা মুহাম্মাদ জালালুদ্দিন\r\n\r\nপ্রকাশনী: মাকতাবায়ে যাকারিয়া\r\n\r\nপৃষ্ঠা: ৩৮৪ | হার্ডকভার | বাংলা\r\n\r\nবিস্তারিত বর্ণনা:\r\nআত্মিক রোগ নিরাময়, ওয়াসওয়াসার মোকাবেলা, নফস নিয়ন্ত্রণ—এই গ্রন্থে সবকিছুই অন্তর্মুখী ও বহির্মুখী দুই দিক থেকেই আলোচিত। ‘তাযকিয়া’ পদ্ধতির জ্ঞানভাণ্ডার, ইহকাল ও পরকালের সফলতার মন্ত্র, এবং সহজ অনুশীলন–টিপস দিয়ে, শাইখুল ইসলামের ভাষায় লেখা এই বই আপনার মনের নড়বড়ে ভাবকে স্থিতিশীল করে তুলবে। প্রতিদিনের চাপ, ঘাত পেতে ভয়, আত্মজ্ঞানের অভাব—এসব কাটিয়ে উঠতে এটি হবে আপনার অমূল্য সঙ্গী।\r\n\r\n৪. শামায়েলে তিরমিজি\r\n\r\nলেখক: ইমাম তিরমিজি (রহ.)\r\n\r\nপ্রকাশনী: মাকতাবায়ে যাকারিয়া\r\n\r\nপৃষ্ঠা: ৮০০ | হার্ডকভার | বাংলা\r\n\r\nবিস্তারিত বর্ণনা:\r\nনবী করীমের দৈহিক অবয়ব, পোশাক-আচরণ, চারিত্রিক বৈশিষ্ট্য ও নৈতিক গুণাবলী সম্পর্কে ৫৬টি অধ্যায়ে সাজানো ৪৫৬টি হাদিস—‘শামায়েলে তিরমিজি’ হাঁড়ভাঙা গবেষণা ও সহজপাঠ্য অনুবাদে। বর্তমান যুগের ধর্মপ্রাণ মানুষদের জন্য এটি হবে সেরা চিত্রপট: নবীর আদর্শ অনুসরণের অনুপ্রেরণা, আত্মসংযমের শিক্ষা ও মানবিক দৃষ্টিভঙ্গি গড়ে তোলার অসামান্য হাতিয়ার।\r\n\r\n৫. হিসনুল মুসলিম\r\n\r\nলেখক: সৈয়দ বিন আলী আল-কাহতানী (মূল রচয়িতা)\r\n\r\nসম্পাদনা ও অনুবাদ: মাকতাবায়ে যাকারিয়া\r\n\r\nপৃষ্ঠা: ১০৫৬ | হার্ডকভার | বাংলা\r\n\r\nবিস্তারিত বর্ণনা:\r\nসকালে ‘বিসমিল্লাহ’ থেকে রাতের শেষ দোয়া পর্যন্ত—প্রতিটি মুহূর্ত আল্লাহর সান্নিধ্য অনুভব করুন ১০৫৬ পাতার এই অমুল্য দোয়া-সংকলনের মাধ্যমে। হৃদয়কে প্রশান্তি, মনকে স্থিতশীলতা এবং দেহকে মানসিক শক্তি প্রদানে ‘হিসনুল মুসলিম’ আপনার প্রতিদিনের ধারাবাহিক আমল। সময়ের অনিশ্চয়তার মাঝে আনুন অটল বিশ্বাসের প্রাচীর—এটি হবে প্রতিটি পরিবারের সৌধপত্র।', 'products/thumbnails/vDg7eyMC76OQHh5edOiLMDmliUKkX7XXqGCPuOy4.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 996, 0, 1, '2026-03-10 02:24:01', '2026-03-30 04:39:27'),
(22, 'বেস্টসেলিং ৬ টি বই', 'fffffffff-0rKH', 'book', 'বেস্টসেলিং ৬ টি বই', 4890.00, 4.00, 0.001, 'fixed', 3891.00, 0, '১. হিসনুল মুসলিম (যিক্‌র ও দু’আ)\r\nসংকলক: সাঈদ বিন আলী বিন ওয়াহফ আল-কাহতানি\r\n\r\nএটি বিশ্বের অন্যতম জনপ্রিয় এবং নির্ভরযোগ্য দু’আর সংকলন। বইটিতে কুরআন এবং সহিহ হাদিস থেকে সংগৃহীত দৈনন্দিন জীবনের প্রয়োজনীয় শত শত দু’আ ও যিকির সন্নিবেশিত করা হয়েছে।\r\n\r\nমূল বিষয়বস্তু: ঘুম থেকে ওঠা, মসজিদে প্রবেশ, খাবার খাওয়া, বিপদ-আপদ, রোগ-শোক এবং সকাল-সন্ধ্যার পঠিতব্য মাসনুন আমল।\r\n\r\nকেন পড়বেন: সুন্নাহ মোতাবেক জীবন পরিচালনা করতে এবং আল্লাহর স্মরণে অন্তরকে সজীব রাখতে এটি একটি চমৎকার পকেট গাইড।\r\n\r\n২. আত্মশুদ্ধি ও তাসাউফ\r\nলেখক: শাইখুল ইসলাম মুফতি তাকি উসমানি (দা.বা.)\r\n\r\nআধ্যাত্মিকতা বা তাসাউফ নিয়ে অনেক ভুল ধারণা প্রচলিত আছে। মুফতি তাকি উসমানি এই বইয়ে শরীয়াহর আলোকে আত্মশুদ্ধির সঠিক পথ বাতলে দিয়েছেন।\r\n\r\nমূল বিষয়বস্তু: অন্তরের ব্যাধি যেমন—অহংকার, হিংসা, রিয়া (লোকদেখানো ইবাদত) থেকে বাঁচার উপায় এবং সবর ও শোকর অর্জনের কৌশল।\r\n\r\nকেন পড়বেন: যান্ত্রিক জীবনে নিজের চরিত্রকে সুন্দর করতে এবং অন্তরের প্রশান্তি খুঁজে পেতে এই বইটি এক অনন্য দিকনির্দেশনা।\r\n\r\n৩. শামায়েলে তিরমিযি\r\nলেখক: ইমাম আবু ঈসা আত-তিরমিযি (রহ.)\r\n\r\nপ্রিয় নবী মুহাম্মদ (সা.)-কে যারা ভালোবাসেন, তাঁদের জন্য এই বইটি পড়া অপরিহার্য। এটি মূলত রাসূলুল্লাহ (সা.)-এর শারীরিক গঠন ও স্বভাব-চরিত্রের এক জীবন্ত চিত্র।\r\n\r\nমূল বিষয়বস্তু: নবীজির (সা.) দৈহিক সৌন্দর্য, তাঁর চুল, পোশাক, হাঁটাচলা, খাদ্যাভ্যাস, কথা বলার ভঙ্গি এবং ইবাদতের বর্ণনা।\r\n\r\nকেন পড়বেন: নবীজিকে (সা.) না দেখেও তাঁর প্রতি ভালোবাসা বাড়াতে এবং তাঁকে মনে মনে কল্পনা করতে এই বইটি সাহায্য করে।\r\n\r\n৪. আত তিব্বুন নববী (Prophetic Medicine)\r\nলেখক: আল্লামা ইবনুল কাইয়্যুম আয-জাওজি (রহ.)\r\n\r\nএটি ইসলামি চিকিৎসাবিজ্ঞানের একটি ধ্রুপদী গ্রন্থ। রাসূলুল্লাহ (সা.) যেসব প্রাকৃতিক উপাদান এবং আমলের মাধ্যমে রোগ নিরাময়ের পরামর্শ দিয়েছেন, তার বিস্তারিত এখানে বর্ণিত হয়েছে।\r\n\r\nমূল বিষয়বস্তু: মধু, কালোজিরা, হিজামা (সিঙা), এবং বিভিন্ন ফল ও হার্বাল উপাদানের গুণাগুণ। পাশাপাশি আধ্যাত্মিক চিকিৎসার (রুকইয়াহ) গুরুত্ব।\r\n\r\nকেন পড়বেন: সুন্নাহভিত্তিক স্বাস্থ্যকর জীবনযাপন এবং প্রাকৃতিক উপায়ে সুস্থ থাকার জ্ঞান অর্জনের জন্য এটি সেরা পছন্দ।\r\n\r\n৫. আল আযকার\r\nলেখক: ইমাম আবু জাকারিয়া ইয়াহইয়া ইবনে শরফ আন-নববী (রহ.)\r\n\r\nপ্রখ্যাত হাদিস বিশারদ ইমাম নববীর এই গ্রন্থটি যিকির ও দু’আর এক বিশাল এনসাইক্লোপিডিয়া।\r\n\r\nমূল বিষয়বস্তু: কেবল দু’আ নয়, বরং কোন ইবাদতের পর কোন আমল করতে হয় এবং জীবনের নানা পরিস্থিতিতে আল্লাহর স্মরণ কীভাবে বজায় রাখা যায়, তার বিস্তারিত হাদিসভিত্তিক আলোচনা।\r\n\r\nকেন পড়বেন: আমলের নির্ভরযোগ্যতা যাচাই করতে এবং যিকিরের তাত্ত্বিক ও ব্যবহারিক জ্ঞান বাড়াতে এটি একটি আকর গ্রন্থ।\r\n\r\n৬. আর রাহীকুল মাখতূম\r\nলেখক: আল্লামা সফিউর রহমান মুবারকপুরী (রহ.)\r\n\r\nএটি বিশ্ববিখ্যাত সীরাত গ্রন্থ, যা রাবেতায়ে আলমে ইসলামি আয়োজিত সীরাত প্রতিযোগিতায় প্রথম স্থান অধিকার করেছিল।\r\n\r\nমূল বিষয়বস্তু: প্রাক-ইসলামি আরবের অবস্থা থেকে শুরু করে নবীজির (সা.) জন্ম, নবুওয়াত লাভ, হিজরত, যুদ্ধ এবং ইসলামের বিজয়ের ধারাবাহিক ইতিহাস।\r\n\r\nকেন পড়বেন: নবীজির (সা.) পূর্ণাঙ্গ জীবনকে ইতিহাসের পাতায় নিখুঁতভাবে দেখার জন্য এর চেয়ে ভালো সীরাত গ্রন্থ আধুনিক যুগে খুব কমই আছে।', '১. হিসনুল মুসলিম (যিক্‌র ও দু’আ)\r\nসংকলক: সাঈদ বিন আলী বিন ওয়াহফ আল-কাহতানি\r\n\r\nএটি বিশ্বের অন্যতম জনপ্রিয় এবং নির্ভরযোগ্য দু’আর সংকলন। বইটিতে কুরআন এবং সহিহ হাদিস থেকে সংগৃহীত দৈনন্দিন জীবনের প্রয়োজনীয় শত শত দু’আ ও যিকির সন্নিবেশিত করা হয়েছে।\r\n\r\nমূল বিষয়বস্তু: ঘুম থেকে ওঠা, মসজিদে প্রবেশ, খাবার খাওয়া, বিপদ-আপদ, রোগ-শোক এবং সকাল-সন্ধ্যার পঠিতব্য মাসনুন আমল।\r\n\r\nকেন পড়বেন: সুন্নাহ মোতাবেক জীবন পরিচালনা করতে এবং আল্লাহর স্মরণে অন্তরকে সজীব রাখতে এটি একটি চমৎকার পকেট গাইড।\r\n\r\n২. আত্মশুদ্ধি ও তাসাউফ\r\nলেখক: শাইখুল ইসলাম মুফতি তাকি উসমানি (দা.বা.)\r\n\r\nআধ্যাত্মিকতা বা তাসাউফ নিয়ে অনেক ভুল ধারণা প্রচলিত আছে। মুফতি তাকি উসমানি এই বইয়ে শরীয়াহর আলোকে আত্মশুদ্ধির সঠিক পথ বাতলে দিয়েছেন।\r\n\r\nমূল বিষয়বস্তু: অন্তরের ব্যাধি যেমন—অহংকার, হিংসা, রিয়া (লোকদেখানো ইবাদত) থেকে বাঁচার উপায় এবং সবর ও শোকর অর্জনের কৌশল।\r\n\r\nকেন পড়বেন: যান্ত্রিক জীবনে নিজের চরিত্রকে সুন্দর করতে এবং অন্তরের প্রশান্তি খুঁজে পেতে এই বইটি এক অনন্য দিকনির্দেশনা।\r\n\r\n৩. শামায়েলে তিরমিযি\r\nলেখক: ইমাম আবু ঈসা আত-তিরমিযি (রহ.)\r\n\r\nপ্রিয় নবী মুহাম্মদ (সা.)-কে যারা ভালোবাসেন, তাঁদের জন্য এই বইটি পড়া অপরিহার্য। এটি মূলত রাসূলুল্লাহ (সা.)-এর শারীরিক গঠন ও স্বভাব-চরিত্রের এক জীবন্ত চিত্র।\r\n\r\nমূল বিষয়বস্তু: নবীজির (সা.) দৈহিক সৌন্দর্য, তাঁর চুল, পোশাক, হাঁটাচলা, খাদ্যাভ্যাস, কথা বলার ভঙ্গি এবং ইবাদতের বর্ণনা।\r\n\r\nকেন পড়বেন: নবীজিকে (সা.) না দেখেও তাঁর প্রতি ভালোবাসা বাড়াতে এবং তাঁকে মনে মনে কল্পনা করতে এই বইটি সাহায্য করে।\r\n\r\n৪. আত তিব্বুন নববী (Prophetic Medicine)\r\nলেখক: আল্লামা ইবনুল কাইয়্যুম আয-জাওজি (রহ.)\r\n\r\nএটি ইসলামি চিকিৎসাবিজ্ঞানের একটি ধ্রুপদী গ্রন্থ। রাসূলুল্লাহ (সা.) যেসব প্রাকৃতিক উপাদান এবং আমলের মাধ্যমে রোগ নিরাময়ের পরামর্শ দিয়েছেন, তার বিস্তারিত এখানে বর্ণিত হয়েছে।\r\n\r\nমূল বিষয়বস্তু: মধু, কালোজিরা, হিজামা (সিঙা), এবং বিভিন্ন ফল ও হার্বাল উপাদানের গুণাগুণ। পাশাপাশি আধ্যাত্মিক চিকিৎসার (রুকইয়াহ) গুরুত্ব।\r\n\r\nকেন পড়বেন: সুন্নাহভিত্তিক স্বাস্থ্যকর জীবনযাপন এবং প্রাকৃতিক উপায়ে সুস্থ থাকার জ্ঞান অর্জনের জন্য এটি সেরা পছন্দ।\r\n\r\n৫. আল আযকার\r\nলেখক: ইমাম আবু জাকারিয়া ইয়াহইয়া ইবনে শরফ আন-নববী (রহ.)\r\n\r\nপ্রখ্যাত হাদিস বিশারদ ইমাম নববীর এই গ্রন্থটি যিকির ও দু’আর এক বিশাল এনসাইক্লোপিডিয়া।\r\n\r\nমূল বিষয়বস্তু: কেবল দু’আ নয়, বরং কোন ইবাদতের পর কোন আমল করতে হয় এবং জীবনের নানা পরিস্থিতিতে আল্লাহর স্মরণ কীভাবে বজায় রাখা যায়, তার বিস্তারিত হাদিসভিত্তিক আলোচনা।\r\n\r\nকেন পড়বেন: আমলের নির্ভরযোগ্যতা যাচাই করতে এবং যিকিরের তাত্ত্বিক ও ব্যবহারিক জ্ঞান বাড়াতে এটি একটি আকর গ্রন্থ।\r\n\r\n৬. আর রাহীকুল মাখতূম\r\nলেখক: আল্লামা সফিউর রহমান মুবারকপুরী (রহ.)\r\n\r\nএটি বিশ্ববিখ্যাত সীরাত গ্রন্থ, যা রাবেতায়ে আলমে ইসলামি আয়োজিত সীরাত প্রতিযোগিতায় প্রথম স্থান অধিকার করেছিল।\r\n\r\nমূল বিষয়বস্তু: প্রাক-ইসলামি আরবের অবস্থা থেকে শুরু করে নবীজির (সা.) জন্ম, নবুওয়াত লাভ, হিজরত, যুদ্ধ এবং ইসলামের বিজয়ের ধারাবাহিক ইতিহাস।\r\n\r\nকেন পড়বেন: নবীজির (সা.) পূর্ণাঙ্গ জীবনকে ইতিহাসের পাতায় নিখুঁতভাবে দেখার জন্য এর চেয়ে ভালো সীরাত গ্রন্থ আধুনিক যুগে খুব কমই আছে।', 'products/thumbnails/ajd2QG263sa6VyucQwE89haZN50PQs7SjcdLfpNc.jpg', NULL, NULL, NULL, 