(30, 'ইমাম নববির চল্লিশ হাদিস', 'imam-nbbir-cllis-hadis-hDPv', 'book', 'ইমাম নববির চল্লিশ হাদিস', 550.00, NULL, 0.001, 'percent', 20.00, 0, 'হাদিস—নবিজির ﷺ পবিত্র বাণী, তাঁর মহিমান্বিত আচরণ, মৌন সমর্থন এবং তাঁর অনন্য জীবনধারার উজ্জ্বল উপমা। তাঁর মুখনিঃসৃত প্রতিটি শব্দ শান্তি ও প্রশান্তির স্নিগ্ধ স্রোতধারা হয়ে হৃদয়ের গভীরে প্রবাহিত হয়। হাদিস অন্তরকে শুদ্ধ করে, মনকে করে উদ্ভাসিত; অন্ধকারাচ্ছন্ন জীবনে জ্বালিয়ে দেয় আলোর প্রদীপ। নবিজির ﷺ হৃদয়ের ঝরনাধারা থেকে ঝরে পড়া মুক্তার দানার মতো প্রতিটি বাণী বিশ্বাসীর অন্তরে আশা ও ভালোবাসার আলো জ্বালায়। হাদিস অধ্যয়নের ভেতর দিয়ে মুসলিমরা নবিজির ﷺ জীবনকে খুব কাছ থেকে দেখার সুযোগ পায়। তাঁর আহ্বান শোনা, তাঁর আচার, আদর্শ ও করুণার সুবাস অনুভব করার সৌভাগ্য লাভ করে।\r\n\r\nনবিজির ﷺ অজস্র হাদিসের ভান্ডার থেকেই ইমাম নববি রাহিমাহুল্লাহ সযত্নে চয়ন করেছেন চল্লিশটি হাদিস। এই চল্লিশটি হাদিস ইসলামের মৌলিক শিক্ষা ও নৈতিকতার ভিত্তি বুঝতে একজন মুমিনের জন্য যথেষ্ট ও উপকারী। বহুকাল ধরেই মুসলিম উম্মাহের মাঝে এই সংকলন জনপ্রিয়তা পেয়ে অপরিহার্য পাঠ্য হয়ে আছে। এই মহামূল্যবান সংকলনটি হৃদয়স্পর্শী ও প্রাঞ্জল ভাষায় ব্যাখ্যা করেছেন সমকালীন বিশিষ্ট আলিম ড. শাইখ সালিহ আল ফাওযান হাফিজাহুল্লাহ। বাংলা অনুবাদে মূলের সৌন্দর্য ও সৌরভ সযত্নে রক্ষিত হয়েছে। নবিজির ﷺ পবিত্র হাদিসের সুধা পান করতে এবং ইসলামের মূল শিক্ষা আত্মস্থ করতে এই বইটি প্রতিটি পাঠকের অনিবার্য সহচর হয়ে থাকবে।', 'হাদিস—নবিজির ﷺ পবিত্র বাণী, তাঁর মহিমান্বিত আচরণ, মৌন সমর্থন এবং তাঁর অনন্য জীবনধারার উজ্জ্বল উপমা। তাঁর মুখনিঃসৃত প্রতিটি শব্দ শান্তি ও প্রশান্তির স্নিগ্ধ স্রোতধারা হয়ে হৃদয়ের গভীরে প্রবাহিত হয়। হাদিস অন্তরকে শুদ্ধ করে, মনকে করে উদ্ভাসিত; অন্ধকারাচ্ছন্ন জীবনে জ্বালিয়ে দেয় আলোর প্রদীপ। নবিজির ﷺ হৃদয়ের ঝরনাধারা থেকে ঝরে পড়া মুক্তার দানার মতো প্রতিটি বাণী বিশ্বাসীর অন্তরে আশা ও ভালোবাসার আলো জ্বালায়। হাদিস অধ্যয়নের ভেতর দিয়ে মুসলিমরা নবিজির ﷺ জীবনকে খুব কাছ থেকে দেখার সুযোগ পায়। তাঁর আহ্বান শোনা, তাঁর আচার, আদর্শ ও করুণার সুবাস অনুভব করার সৌভাগ্য লাভ করে।\r\n\r\nনবিজির ﷺ অজস্র হাদিসের ভান্ডার থেকেই ইমাম নববি রাহিমাহুল্লাহ সযত্নে চয়ন করেছেন চল্লিশটি হাদিস। এই চল্লিশটি হাদিস ইসলামের মৌলিক শিক্ষা ও নৈতিকতার ভিত্তি বুঝতে একজন মুমিনের জন্য যথেষ্ট ও উপকারী। বহুকাল ধরেই মুসলিম উম্মাহের মাঝে এই সংকলন জনপ্রিয়তা পেয়ে অপরিহার্য পাঠ্য হয়ে আছে। এই মহামূল্যবান সংকলনটি হৃদয়স্পর্শী ও প্রাঞ্জল ভাষায় ব্যাখ্যা করেছেন সমকালীন বিশিষ্ট আলিম ড. শাইখ সালিহ আল ফাওযান হাফিজাহুল্লাহ। বাংলা অনুবাদে মূলের সৌন্দর্য ও সৌরভ সযত্নে রক্ষিত হয়েছে। নবিজির ﷺ পবিত্র হাদিসের সুধা পান করতে এবং ইসলামের মূল শিক্ষা আত্মস্থ করতে এই বইটি প্রতিটি পাঠকের অনিবার্য সহচর হয়ে থাকবে।', 'products/thumbnails/QHUvYuQr05H02nFJALpcLClVwurwIYNnA4nFcW5o.webp', NULL, 424, 'Sep-2025', 'Bangla', 'Bangladesh', NULL, NULL, NULL, NULL, NULL, 998, 0, 1, '2026-03-12 15:47:48', '2026-03-30 13:12:16'),
(31, 'তাফসীরে মাআরেফুল কোরআন (১-৩ খণ্ড)', 'tafseere-maareful-koran-1-3-khnd-3Ebq', 'book', 'তাফসীরে মাআরেফুল কোরআন (১-৩ খণ্ড)', 2400.00, NULL, 0.001, 'percent', 25.00, 0, 'লেখক : হযরত মাওলানা মুফতি মুহাম্মাদ শফি\r\nপ্রকাশনী : মাসিক মদীনা পাবলিকেশান্স\r\nবিষয় : তাফসীরুল কুরআন\r\nকভার : হার্ড কভার\r\nভাষা : বাংলা', 'লেখক : হযরত মাওলানা মুফতি মুহাম্মাদ শফি\r\nপ্রকাশনী : মাসিক মদীনা পাবলিকেশান্স\r\nবিষয় : তাফসীরুল কুরআন\r\nকভার : হার্ড কভার\r\nভাষা : বাংলা', 'products/thumbnails/Fk6qowIQ7egdK7WrmbP7NlFJzEziSr43thIz4kbR.webp', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 997, 0, 1, '2026-03-12 15:52:23', '2026-03-30 04:53:09'),
(32, 'সিরাতুন নবি সা. (১-৩ খণ্ড পূর্ণ)', 'siratun-nbi-sa-1-3-khnd-puurn-LzAw', 'book', 'সিরাতুন নবি সা. (১-৩ খণ্ড পূর্ণ)', 2300.00, NULL, 0.001, 'percent', 25.00, 0, 'অনুবাদক টিম : নুরুযযামান নাহিদ, আবদুর রশীদ তারাপাশী, মহিউদ্দিন কাসেমী\r\nসম্পাদনা টিম : আবদুর রশীদ তারাপাশী, আহসান ইলিয়াস, সালমান মোহাম্মদ ,আবুল কালাম আজাদ\r\n\r\nআমাদের প্রিয়নবি মুহাম্মাদ সাল্লাল্লাহু আলাইহি ওয়া সাল্লাম; জীবনের শুদ্ধতার মাপকাঠি নবিজির আদর্শ। তাই তাঁর জীবনী বা সিরাত অধ্যয়ন করা প্রত্যেক মুসলমানের জন্য অতি জরুরি। রাসুলের জীবনী অধ্যয়ন করলে একজন মুসলমান তাঁর জীবনের সূক্ষ্মাতিসূক্ষ্ম বিষয় তথা জন্ম থেকে মৃত্যু—শৈশবকাল, যৌবনকাল, দাওয়াত, রাজনীতি, রাষ্ট্র পরিচালনা, জিহাদসহ জীবনের সব বিষয়ের বিস্তারিত পথনির্দেশনা পাবে।\r\n\r\nবিশ্বখ্যাত ইতিহাস ও সিরাত গবেষক ড. আলি মুহাম্মাদ সাল্লাবি বিশুদ্ধ বর্ণনার আলোকে নবিজির বিস্তারিত জীবনী রচনা করেছেন। বইটির গুরুত্ব ও প্রয়োজনীয়তার ব্যাপারে এতটুকু আমরা আপনাদের জানাচ্ছি যে, অতীতের শত সিরাতের সারনির্যাস ও বর্তমান সময়ের রাজনৈতিক অস্থিরতার সমাধান এতে আলোচনা করা হয়েছে। এমন বিশ্লেষণধর্মী-শিক্ষামূলক আরেকটি সিরাতগ্রন্থ আমাদের নজরে পড়েনি।\r\n\r\nমূল গ্রন্থটি আরবি ভাষায় রচিত। বাংলা ভাষায় বিশ্লেষণধর্মী বিশুদ্ধ সিরাতের শূন্যতা পূরণে ‘কালান্তর প্রকাশনী’ গ্রন্থটির অনুবাদ প্রকাশ করে তিন খণ্ডে আপনাদের হাতে তুলে দিচ্ছে।', 'অনুবাদক টিম : নুরুযযামান নাহিদ, আবদুর রশীদ তারাপাশী, মহিউদ্দিন কাসেমী\r\nসম্পাদনা টিম : আবদুর রশীদ তারাপাশী, আহসান ইলিয়াস, সালমান মোহাম্মদ ,আবুল কালাম আজাদ\r\n\r\nআমাদের প্রিয়নবি মুহাম্মাদ সাল্লাল্লাহু আলাইহি ওয়া সাল্লাম; জীবনের শুদ্ধতার মাপকাঠি নবিজির আদর্শ। তাই তাঁর জীবনী বা সিরাত অধ্যয়ন করা প্রত্যেক মুসলমানের জন্য অতি জরুরি। রাসুলের জীবনী অধ্যয়ন করলে একজন মুসলমান তাঁর জীবনের সূক্ষ্মাতিসূক্ষ্ম বিষয় তথা জন্ম থেকে মৃত্যু—শৈশবকাল, যৌবনকাল, দাওয়াত, রাজনীতি, রাষ্ট্র পরিচালনা, জিহাদসহ জীবনের সব বিষয়ের বিস্তারিত পথনির্দেশনা পাবে।\r\n\r\nবিশ্বখ্যাত ইতিহাস ও সিরাত গবেষক ড. আলি মুহাম্মাদ সাল্লাবি বিশুদ্ধ বর্ণনার আলোকে নবিজির বিস্তারিত জীবনী রচনা করেছেন। বইটির গুরুত্ব ও প্রয়োজনীয়তার ব্যাপারে এতটুকু আমরা আপনাদের জানাচ্ছি যে, অতীতের শত সিরাতের সারনির্যাস ও বর্তমান সময়ের রাজনৈতিক অস্থিরতার সমাধান এতে আলোচনা করা হয়েছে। এমন বিশ্লেষণধর্মী-শিক্ষামূলক আরেকটি সিরাতগ্রন্থ আমাদের নজরে পড়েনি।\r\n\r\nমূল গ্রন্থটি আরবি ভাষায় রচিত। বাংলা ভাষায় বিশ্লেষণধর্মী বিশুদ্ধ সিরাতের শূন্যতা পূরণে ‘কালান্তর প্রকাশনী’ গ্রন্থটির অনুবাদ প্রকাশ করে তিন খণ্ডে আপনাদের হাতে তুলে দিচ্ছে।', 'products/thumbnails/r9OU5uWwDxLE8VXk41UnTBRIEwC2deLvvbeXPzvI.webp', NULL, 1448, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 994, 0, 1, '2026-03-12 15:56:10', '2026-03-31 01:21:09'),
(33, 'আদাবুল মু‘আশারাত', 'adabul-muasarat-ykMQ', 'book', 'আদাবুল মু‘আশারাত', 350.00, NULL, 0.001, 'percent', 30.00, 0, 'অনুবাদক: মাওলানা আবু আফফান নূরুজ্জামান', 'অনুবাদক: মাওলানা আবু আফফান নূরুজ্জামান', 'products/thumbnails/OTy47VHeGkjaTchS8LQdRbzePDR1T7R3lWvtjKhs.jpg', NULL, 240, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 996, 0, 1, '2026-03-12 16:05:22', '2026-03-30 04:22:42'),
(34, 'আল-আদাবুল মুফরাদ (দুই খণ্ড বক্সসহ)', 'al-adabul-mufrad-dui-khnd-bkssh-z63y', 'book', 'আল-আদাবুল মুফরাদ (দুই খণ্ড বক্সসহ)', 1100.00, 500.00, 0.001, 'fixed', 401.00, 1, 'উত্তম আদব-আখলাক ও শিষ্টাচার সংক্রান্ত ১২০০ বছর আগের প্রাচীন কিতাব।\r\n✅ একজন মুসলমান কিভাবে তার জীবন এবং পরিবারের সন্তানদের উত্তম আদব, শিষ্টাচার ও আখলাক শিক্ষা দিবেন ১২০০ বছর পুর্বে ইমাম বুখারীর হাদীসের সংকলন থেকে আদাবুল মুফরাদ নামে এই কিতাবটি অনুবাদ করা হয়েছে ।\r\n\r\n📓📓 সহিহ বুখারির পর ইমাম বুখারি রহ. এর বিখ্যাত কিতাব হচ্ছে—আল-আদাবুল মুফরাদ। এখানে দৈনন্দিন জীবনে আদব-আখলাক,\r\nআচার-আচরণ বিষয়ক মোট ১৩৫০ টি হাদিস রয়েছে। প্রতিটি হাদিস তাহকিক করেছেন দুজন বিখ্যাত মুহাক্কিক, শাইখ নাসিরুদ্দীন\r\nআলবানি রহ. ও শাইখ শুআইব আরনাউত রহ.।\r\n\r\n🕌🕌 নববি ভাববোধ মানবজীবনের প্রতিটি ক্ষেত্রেই সুগন্ধি ছড়ায়, অন্ধকারকে আলোকিত করে, অসুন্দরকে সুন্দর করে।\r\nতাই আমাদের উচিত নিজেদের আখলাককে নববি আদর্শে সুসজ্জিত করে তোলা। নববি আদর্শ এবং উত্তম আখলাক ও চরিত্রের বিবিধ বিষয় নিয়ে চমৎকার একটি গ্রন্থনা হচ্ছে এ বইটি।\r\n\r\n❤️❤️ আরবি ইবারত+বাংলা অনুবাদ+দুজন মুহাক্কিকের তাহকিক+দুআর বাংলা উচ্চারণ+বিষয়ভিত্তিক আকারে সাজানো\r\nবইটি', 'উত্তম আদব-আখলাক ও শিষ্টাচার সংক্রান্ত ১২০০ বছর আগের প্রাচীন কিতাব।\r\n✅ একজন মুসলমান কিভাবে তার জীবন এবং পরিবারের সন্তানদের উত্তম আদব, শিষ্টাচার ও আখলাক শিক্ষা দিবেন ১২০০ বছর পুর্বে ইমাম বুখারীর হাদীসের সংকলন থেকে আদাবুল মুফরাদ নামে এই কিতাবটি অনুবাদ করা হয়েছে ।\r\n\r\n📓📓 সহিহ বুখারির পর ইমাম বুখারি রহ. এর বিখ্যাত কিতাব হচ্ছে—আল-আদাবুল মুফরাদ। এখানে দৈনন্দিন জীবনে আদব-আখলাক,\r\nআচার-আচরণ বিষয়ক মোট ১৩৫০ টি হাদিস রয়েছে। প্রতিটি হাদিস তাহকিক করেছেন দুজন বিখ্যাত মুহাক্কিক, শাইখ নাসিরুদ্দীন\r\nআলবানি রহ. ও শাইখ শুআইব আরনাউত রহ.।\r\n\r\n🕌🕌 নববি ভাববোধ মানবজীবনের প্রতিটি ক্ষেত্রেই সুগন্ধি ছড়ায়, অন্ধকারকে আলোকিত করে, অসুন্দরকে সুন্দর করে।\r\nতাই আমাদের উচিত নিজেদের আখলাককে নববি আদর্শে সুসজ্জিত করে তোলা। নববি আদর্শ এবং উত্তম আখলাক ও চরিত্রের বিবিধ বিষয় নিয়ে চমৎকার একটি গ্রন্থনা হচ্ছে এ বইটি।\r\n\r\n❤️❤️ আরবি ইবারত+বাংলা অনুবাদ+দুজন মুহাক্কিকের তাহকিক+দুআর বাংলা উচ্চারণ+বিষয়ভিত্তিক আকারে সাজানো\r\nবইটি', 'products/thumbnails/2iUxYGyCct80oyvW9wEYvKQv72kg7P4AX84agJYY.jpg', NULL, 736, '1st', 'Bangla', 'Bangladesh', NULL, NULL, NULL, NULL, NULL, 999, 0, 1, '2026-03-25 00:41:09', '2026-03-30 16:49:30'),
(35, 'সহীহ্ বুখারী ৪ ভলিউমে ( ১ম-১০ খন্ড )', 'sheeh-bukharee-4-vliume-1m-10-khnd-WT2u', 'book', 'সহীহ্ বুখারী ৪ ভলিউমে ( ১ম-১০ খন্ড )', 3800.00, NULL, 0.001, 'fixed', 2701.00, 0, 'প্রসিদ্ধ হাদিস গ্রন্থ সহীহ বুখারী শরীফ (১ থেকে ১০ খণ্ড একত্রে - ৪টি বইয়ে) অফার মূল্য: ১০৯৯৳ (৭৫%ছাড়ে)। রাসূল সঃ এর সুন্নাত জানার জন্য এবং সহীহ হাদীসের উপর আমল করার জন্য প্রসিদ্ধ সহীহ বুখারী শরীফ (১ থেকে ১০ খণ্ড একত্রে) গ্রন্থ এক যুগান্তকারী সংকলন । অতি সাধারন পাঠকেরাও এই গ্রন্থের অনুবাদ পরতে পারবে এবং বুজতে পারবে । এতে করে তাদের দুর্বল ও জাল হাদিসের কবলে পরার সম্ভাবনা থাকবেনা ।\r\n\r\n🕋 আপনার ঘরে কি পবিত্র কুরআনের পর সবচেয়ে বিশুদ্ধ ও নির্ভরযোগ্য গ্রন্থটি আছে? এমন একটি গ্রন্থ, যা আপনার পরিবারকে সরাসরি রাসূলুল্লাহ ﷺ-এর সুন্নাহর সাথে যুক্ত করবে? ইমাম বুখারী (রহ.)-এর অসামান্য কীর্তি ‘সহীহ বুখারী শরীফ’ শুধু একটি হাদিস গ্রন্থ নয়, এটি মুসলিম উম্মাহর জন্য এক আলোকবর্তিকা। এখানে নেই কোনো দুর্বল বা বানোয়াট হাদিসের সংশয়। প্রতিটি শব্দ, প্রতিটি বাক্য হলো রাসূল ﷺ-এর রেখে যাওয়া আমানত, যা আপনার ঈমান ও আমলের ভিত্তিকে করবে পর্বতের মতো \r\n\r\nএকবার কল্পনা করুন, আপনার পুরো পরিবার একসাথে বসে এই গ্রন্থ থেকে জ্ঞানার্জন করছে। আপনার সন্তানেরা শিখছে নবীর ﷺ আদর্শ, আপনার ঘর ভরে উঠছে আল্লাহর রহমতে। জীবনের যেকোনো সমস্যায়, যেকোনো সিদ্ধান্তে আপনি সরাসরি সমাধান খুঁজে পাচ্ছেন সুন্নাহর আলোয়। এই ১০ খণ্ডের সংকলনটি আপনার লাইব্রেরির शोभा নয়, বরং আপনার এবং আপনার পরিবারের জন্য দুনিয়া ও আখিরাতের নাজাতের উসিলা। এটি আপনার জন্য এক অমূল্য সদকায়ে জারিয়া। \r\n\r\n \r\n\r\nবই : সহীহ বুখারী শরীফ (১ থেকে ১০ খণ্ড একত্রে)\r\n\r\nমূল লেখক : ইমাম মুহাম্মদ ইবনে ইসমাইল বোখারী (র)\r\n\r\nমুদ্রিত মূল্য:৩,৮০০৳\r\n\r\nবিক্রয় মূল্য: ১০৯৯৳ (৭৫%ছাড়ে)\r\n\r\n#বইয়ের কোয়ালিটি: প্রিমিয়াম কোয়ালিটি কাগজ এবং হার্ডকভার বাইন্ডিং', 'প্রসিদ্ধ হাদিস গ্রন্থ সহীহ বুখারী শরীফ (১ থেকে ১০ খণ্ড একত্রে - ৪টি বইয়ে) অফার মূল্য: ১০৯৯৳ (৭৫%ছাড়ে)। রাসূল সঃ এর সুন্নাত জানার জন্য এবং সহীহ হাদীসের উপর আমল করার জন্য প্রসিদ্ধ সহীহ বুখারী শরীফ (১ থেকে ১০ খণ্ড একত্রে) গ্রন্থ এক যুগান্তকারী সংকলন । অতি সাধারন পাঠকেরাও এই গ্রন্থের অনুবাদ পরতে পারবে এবং বুজতে পারবে । এতে করে তাদের দুর্বল ও জাল হাদিসের কবলে পরার সম্ভাবনা থাকবেনা ।\r\n\r\n🕋 আপনার ঘরে কি পবিত্র কুরআনের পর সবচেয়ে বিশুদ্ধ ও নির্ভরযোগ্য গ্রন্থটি আছে? এমন একটি গ্রন্থ, যা আপনার পরিবারকে সরাসরি রাসূলুল্লাহ ﷺ-এর সুন্নাহর সাথে যুক্ত করবে? ইমাম বুখারী (রহ.)-এর অসামান্য কীর্তি ‘সহীহ বুখারী শরীফ’ শুধু একটি হাদিস গ্রন্থ নয়, এটি মুসলিম উম্মাহর জন্য এক আলোকবর্তিকা। এখানে নেই কোনো দুর্বল বা বানোয়াট হাদিসের সংশয়। প্রতিটি শব্দ, প্রতিটি বাক্য হলো রাসূল ﷺ-এর রেখে যাওয়া আমানত, যা আপনার ঈমান ও আমলের ভিত্তিকে করবে পর্বতের মতো \r\n\r\nএকবার কল্পনা করুন, আপনার পুরো পরিবার একসাথে বসে এই গ্রন্থ থেকে জ্ঞানার্জন করছে। আপনার সন্তানেরা শিখছে নবীর ﷺ আদর্শ, আপনার ঘর ভরে উঠছে আল্লাহর রহমতে। জীবনের যেকোনো সমস্যায়, যেকোনো সিদ্ধান্তে আপনি সরাসরি সমাধান খুঁজে পাচ্ছেন সুন্নাহর আলোয়। এই ১০ খণ্ডের সংকলনটি আপনার লাইব্রেরির शोभा নয়, বরং আপনার এবং আপনার পরিবারের জন্য দুনিয়া ও আখিরাতের নাজাতের উসিলা। এটি আপনার জন্য এক অমূল্য সদকায়ে জারিয়া। \r\n\r\n \r\n\r\nবই : সহীহ বুখারী শরীফ (১ থেকে ১০ খণ্ড একত্রে)\r\n\r\nমূল লেখক : ইমাম মুহাম্মদ ইবনে ইসমাইল বোখারী (র)\r\n\r\nমুদ্রিত মূল্য:৩,৮০০৳\r\n\r\nবিক্রয় মূল্য: ১০৯৯৳ (৭৫%ছাড়ে)\r\n\r\n#বইয়ের কোয়ালিটি: প্রিমিয়াম কোয়ালিটি কাগজ এবং হার্ডকভার বাইন্ডিং', 'products/thumbnails/FgHzC8VjVWjzd54rUJot7MUzQapZRGKUyNuEzOmq.jpg', NULL, 2432, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 10000, 0, 1, '2026-03-25 00:50:18', '2026-03-25 00:52:00'),
(36, 'ফতোয়ায়ে হানাফিয়া প্রিমিয়াম কোয়ালিটি (২খন্ডে)', 'ftoyaye-hanafiya-primiyam-koyaliti-2khnde-K9YX', 'book', 'ফতোয়ায়ে হানাফিয়া প্রিমিয়াম কোয়ালিটি (২খন্ডে)', 2100.00, NULL, 0.001, 'fixed', 1401.00, 0, 'হানাফি মাজহাব অনুসারে তিন হাজারের বেশি গুরুত্বপূর্ণ মাসয়ালা সম্বলিত নির্ভরযোগ্য ফতোয়ার কিতাব...\r\n\r\nফতোয়া দেওয়া বা লেখা সহজ কথা নয়। সমাজে নির্ভরযোগ্য মুফতীগন এ ব্যাপারে অনেক অবদান রাখছেন। এতদ সত্ত্বেও আমার এ বিষয়ে কলম ধরনের কারণ শুধুমাত্র সাধারণ মানুষের উপকার সাধন করা।বাংলাদেশের সর্বত্রই মুফতীগন বিরাজমান, কিন্ত সাধারণ মানুষ সচরাচর তানাদের নিকট গিয়ে মসয়ালার সমাধান খুঁজতে অনেক সময় ব্যর্থ হন।\r\nমুফতীগন অনেক সময় ইলমী ও আমলী ব্যস্ততায় নিমজ্জিত থাকেন, আবার অনেকে জনসাধারণের থেকে দূরে অবস্থান করেন।\r\n\r\nমুসলিম ব্যক্তিগন তাদের জীবন চালনার পথে বিভিন্ন শরয়ী মাসায়েল এর সম্মুখীন হয়ে থাকেন, যা তাদের জানা থাকে না । তাই আমি নগন্য অসংখ্য ফতোয়ার কিতাব মন্হন করে হানাফী মাযহাব মতে সিদ্ধান্ত মূলক মতামতের ভিত্তিতে রেফারেন্সসহ \"ফতোয়ায়ে হানিফায়া\" নামক কিতাব সংকলন করি।\r\nএ কিতাবের মধ্যে ৩২০৯ টি গুরুত্বপূর্ণ মাসায়েল সংকলন করা হয়েছে। এছাড়াও ফিকাহ শাস্ত্রের ইতিহাস ও পরিচয়, বিভিন্ন দেশের মুফতীগনের বর্ণনা, ফিকাহ সংকলনের প্রয়োজনীয়তা, আইম্মায়ে মুজতাহেদীনের সংক্ষিপ্ত পরিচিত তথা ইমাম আবু হানিফা(র), ইমাম শাফেয়ী (র), ইমাম মালেক (র), ইমাম আহমাদ ইবনে হাম্বল (র) । ইত্যাদি', 'হানাফি মাজহাব অনুসারে তিন হাজারের বেশি গুরুত্বপূর্ণ মাসয়ালা সম্বলিত নির্ভরযোগ্য ফতোয়ার কিতাব...\r\n\r\nফতোয়া দেওয়া বা লেখা সহজ কথা নয়। সমাজে নির্ভরযোগ্য মুফতীগন এ ব্যাপারে অনেক অবদান রাখছেন। এতদ সত্ত্বেও আমার এ বিষয়ে কলম ধরনের কারণ শুধুমাত্র সাধারণ মানুষের উপকার সাধন করা।বাংলাদেশের সর্বত্রই মুফতীগন বিরাজমান, কিন্ত সাধারণ মানুষ সচরাচর তানাদের নিকট গিয়ে মসয়ালার সমাধান খুঁজতে অনেক সময় ব্যর্থ হন।\r\nমুফতীগন অনেক সময় ইলমী ও আমলী ব্যস্ততায় নিমজ্জিত থাকেন, আবার অনেকে জনসাধারণের থেকে দূরে অবস্থান করেন।\r\n\r\nমুসলিম ব্যক্তিগন তাদের জীবন চালনার পথে বিভিন্ন শরয়ী মাসায়েল এর সম্মুখীন হয়ে থাকেন, যা তাদের জানা থাকে না । তাই আমি নগন্য অসংখ্য ফতোয়ার কিতাব মন্হন করে হানাফী মাযহাব মতে সিদ্ধান্ত মূলক মতামতের ভিত্তিতে রেফারেন্সসহ \"ফতোয়ায়ে হানিফায়া\" নামক কিতাব সংকলন করি।\r\nএ কিতাবের মধ্যে ৩২০৯ টি গুরুত্বপূর্ণ মাসায়েল সংকলন করা হয়েছে। এছাড়াও ফিকাহ শাস্ত্রের ইতিহাস ও পরিচয়, বিভিন্ন দেশের মুফতীগনের বর্ণনা, ফিকাহ সংকলনের প্রয়োজনীয়তা, আইম্মায়ে মুজতাহেদীনের সংক্ষিপ্ত পরিচিত তথা ইমাম আবু হানিফা(র), ইমাম শাফেয়ী (র), ইমাম মালেক (র), ইমাম আহমাদ ইবনে হাম্বল (র) । ইত্যাদি', 'products/thumbnails/zbZLS0cfOjGLnjj99DoCpdiHrYI38mLHsQdYyKhI.jpg', NULL, 1176, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 985, 0, 1, '2026-03-25 01:01:12', '2026-03-30 16:52:03'),
(37, 'আল কুরআন ও আধুনিক বিজ্ঞান (হার্ডকভার)', 'al-kuran-oo-adhunik-bijngan-hardkvar-ZGjG', 'book', 'আল কুরআন ও আধুনিক বিজ্ঞান (হার্ডকভার)', 200.00, NULL, 0.001, 'percent', 32.00, 0, '#রাসুল (সাঃ) এর সময় থেকেই অনেক মানুষ কুরআনকে আল্লাহর বাণী হিসেবে গ্রহণ করেন না। তাঁরা মনে করেন কুরআন রাসুল (সাঃ) এর রচিত গ্রন্থ। অথচ কুরআনের মধ্যেই প্রমাণ রয়েছে যে, এমন গ্রন্থ রচনা করা মানব বা জ্বিন কারো পক্ষেই ব্যক্তিগত কিংবা সামষ্টিকভাবে সম্ভব নয়। কুরআনে গাণিতিক যুক্তির উপস্থিতিই এর সর্বসাম্প্রতিক প্রমাণ। এই বইয়ের গ্রন্থকার ‘আহমেদ দিদাত’ কুরআনের বিভিন্ন আয়াত এবং শব্দ বিশ্লেষণ করে কুরআনের অভ্যন্তরে ১৯ তথা গণিতের এক বিস্ময়কর উপস্থিতি প্রকাশ করে প্রমাণ করেছেন যে কুরআন এক রহস্যময় সৃষ্টি। বইটি পড়ে পাঠক উপলব্দি করবেন যে, কুরআন কোন সাধারন গ্রন্থ নয় এটি গানিতিক রহস্যময় এক অলৌকিক গ্রন্থ।', '#রাসুল (সাঃ) এর সময় থেকেই অনেক মানুষ কুরআনকে আল্লাহর বাণী হিসেবে গ্রহণ করেন না। তাঁরা মনে করেন কুরআন রাসুল (সাঃ) এর রচিত গ্রন্থ। অথচ কুরআনের মধ্যেই প্রমাণ রয়েছে যে, এমন গ্রন্থ রচনা করা মানব বা জ্বিন কারো পক্ষেই ব্যক্তিগত কিংবা সামষ্টিকভাবে সম্ভব নয়। কুরআনে গাণিতিক যুক্তির উপস্থিতিই এর সর্বসাম্প্রতিক প্রমাণ। এই বইয়ের গ্রন্থকার ‘আহমেদ দিদাত’ কুরআনের বিভিন্ন আয়াত এবং শব্দ বিশ্লেষণ করে কুরআনের অভ্যন্তরে ১৯ তথা গণিতের এক বিস্ময়কর উপস্থিতি প্রকাশ করে প্রমাণ করেছেন যে কুরআন এক রহস্যময় সৃষ্টি। বইটি পড়ে পাঠক উপলব্দি করবেন যে, কুরআন কোন সাধারন গ্রন্থ নয় এটি গানিতিক রহস্যময় এক অলৌকিক গ্রন্থ।', 'products/thumbnails/Ef1kWyQRNPWTktk6rU0WHM0vrLd8UWn9k1DoDpv5.webp', NULL, 80, NULL, 'Bangla', NULL, NULL, NULL, NULL, NULL, NULL, 1000, 0, 1, '2026-03-25 23:52:18', '2026-03-25 23:52:18'),
