(39, 'বাইবেল কুরআন ও বিজ্ঞান', 'baibel-kuran-oo-bijngan-4uW9', 'book', 'বাইবেল কুরআন ও বিজ্ঞান', 450.00, NULL, 0.001, 'percent', 30.00, 0, 'বাইবেল কোরআন ও বিজ্ঞান পৃথিবী বিখ্যাত একটি গ্রন্থ। গ্রন্থটি রচনা করেছেন ফ্রান্সের প্রখ্যাত সার্জন, বৈজ্ঞানিক ও গবেষক ডাঃ মরিস বুকাইলি। ফরাসী ভাষায় রচিত তাঁর “লা বাইবেল, লা কোরআন য়েট লা সাইন্স” নামক বইখানি সর্বপ্রথম ১৯৭৬ সালের মে মাসে প্যারিসে প্রকাশিত হলে সঙ্গে সঙ্গে সুধীজনের দৃষ্টি আকর্ষণ করে। ইংরেজী ও আরবি সহ পৃথিবীর বহু ভাষায় বইটি অনুদিত হয়। এই বইয়ে তিনি আধুনিক বৈজ্ঞানিক গবেষণা থেকে পাওয়া জ্ঞানের সঙ্গে বাইবেলের বর্ণনার অসঙ্গতি এবং কুরআনের বর্ণনার সঙ্গতি সুন্দরভাবে তুলে ধরেছেন। বিজ্ঞানের এ চরম উৎকর্ষতার যুগে প্রকৃত সত্যকে যারা আবিষ্কার করতে চান এ বইটি তাদের প্রভূত উপকারে আসছে বিধায় দুনিয়া জুড়ে বইটি ব্যাপকভাবে আলোচিত ও প্রশংসিত হচ্ছে।বইটি পড়ে পাঠকের নতুন চিন্তার দুয়ার খুলবে, ইনশা’আল্লাহ', 'বাইবেল কোরআন ও বিজ্ঞান পৃথিবী বিখ্যাত একটি গ্রন্থ। গ্রন্থটি রচনা করেছেন ফ্রান্সের প্রখ্যাত সার্জন, বৈজ্ঞানিক ও গবেষক ডাঃ মরিস বুকাইলি। ফরাসী ভাষায় রচিত তাঁর “লা বাইবেল, লা কোরআন য়েট লা সাইন্স” নামক বইখানি সর্বপ্রথম ১৯৭৬ সালের মে মাসে প্যারিসে প্রকাশিত হলে সঙ্গে সঙ্গে সুধীজনের দৃষ্টি আকর্ষণ করে। ইংরেজী ও আরবি সহ পৃথিবীর বহু ভাষায় বইটি অনুদিত হয়। এই বইয়ে তিনি আধুনিক বৈজ্ঞানিক গবেষণা থেকে পাওয়া জ্ঞানের সঙ্গে বাইবেলের বর্ণনার অসঙ্গতি এবং কুরআনের বর্ণনার সঙ্গতি সুন্দরভাবে তুলে ধরেছেন। বিজ্ঞানের এ চরম উৎকর্ষতার যুগে প্রকৃত সত্যকে যারা আবিষ্কার করতে চান এ বইটি তাদের প্রভূত উপকারে আসছে বিধায় দুনিয়া জুড়ে বইটি ব্যাপকভাবে আলোচিত ও প্রশংসিত হচ্ছে।বইটি পড়ে পাঠকের নতুন চিন্তার দুয়ার খুলবে, ইনশা’আল্লাহ', 'products/thumbnails/hBtbaP7Uh2bO4vJJARQlXqVzibnafZ5FWUNMjQOK.webp', NULL, 352, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 989, 0, 1, '2026-03-26 00:58:19', '2026-03-30 15:13:36'),
(40, 'নবিয়ে রহমত', 'nbiye-rhmt-oDuG', 'book', 'নবিয়ে রহমত', 1150.00, NULL, 0.001, 'fixed', 660.00, 0, '❤️ নবীজির প্রতি ভালোবাসা ছাড়া ঈমান পূর্ণ হয় না, আর যাকে চিনি না তাকে ভালোবাসবো কীভাবে? যিনি শিশুকালে দুধপান করার সময়ও ইনসাফ করতেন। যিনি পাথরের আঘাতে জর্জরিত হয়েও বদদোয়া করেননি, উল্টো তাদের কল্যাণের জন্য দুআ করেছেন। তিনি হলেন আমাদের প্রিয় নবী, ‘নবীয়ে রহমত’।রাসূলুল্লাহ ﷺ-এর জীবন কেবল ইতিহাস নয়, বরং অন্ধকার থেকে আলোতে ফেরার এক জীবন্ত বিপ্লব। শায়খুল ইসলাম সাইয়েদ আবুল হাসান আলী নদভী (রহ.) রচিত ‘নবীয়ে রহমত’ গ্রন্থটি সেই বিপ্লবেরই এক প্রামাণ্য দলিল। এটি সেই সিরাত গ্রন্থ যা আরব বিশ্বের কলেজ-ভার্সিটিতেও পাঠ্য!\r\n\r\n📖 কেন এই বইটি আপনার সংগ্রহে থাকা আবশ্যক?\r\n✅ বিশ্ববিখ্যাত লেখকের লেখনী: মুসলিম বিশ্বের অন্যতম শ্রেষ্ঠ চিন্তাবিদ ও ইতিহাসবেত্তার অমর সৃষ্টি।\r\n✅ ঐতিহাসিক প্রেক্ষাপট: রাসূল ﷺ-এর আগমনের আগে রোম ও পারস্য সাম্রাজ্যের পতন এবং আরবের জাহেলিয়াতের নিখুঁত চিত্র।\r\n✅ আধুনিক জীবনের পাথেয়: চৌদ্দশ বছর আগের আদর্শকে বর্তমান সময়ের প্রেক্ষাপটে কিভাবে প্রয়োগ করা যায়, তার দিকনির্দেশনা।\r\n✅ সহজবোধ্য অনুবাদ: অত্যন্ত সুললিত বাংলা অনুবাদ, যা সর্বস্তরের পাঠকদের জন্য সহজপাঠ্য।💰 অফার মূল্য: মাত্র ৪৯০ টাকা।', '❤️ নবীজির প্রতি ভালোবাসা ছাড়া ঈমান পূর্ণ হয় না, আর যাকে চিনি না তাকে ভালোবাসবো কীভাবে? যিনি শিশুকালে দুধপান করার সময়ও ইনসাফ করতেন। যিনি পাথরের আঘাতে জর্জরিত হয়েও বদদোয়া করেননি, উল্টো তাদের কল্যাণের জন্য দুআ করেছেন। তিনি হলেন আমাদের প্রিয় নবী, ‘নবীয়ে রহমত’।রাসূলুল্লাহ ﷺ-এর জীবন কেবল ইতিহাস নয়, বরং অন্ধকার থেকে আলোতে ফেরার এক জীবন্ত বিপ্লব। শায়খুল ইসলাম সাইয়েদ আবুল হাসান আলী নদভী (রহ.) রচিত ‘নবীয়ে রহমত’ গ্রন্থটি সেই বিপ্লবেরই এক প্রামাণ্য দলিল। এটি সেই সিরাত গ্রন্থ যা আরব বিশ্বের কলেজ-ভার্সিটিতেও পাঠ্য!\r\n\r\n📖 কেন এই বইটি আপনার সংগ্রহে থাকা আবশ্যক?\r\n✅ বিশ্ববিখ্যাত লেখকের লেখনী: মুসলিম বিশ্বের অন্যতম শ্রেষ্ঠ চিন্তাবিদ ও ইতিহাসবেত্তার অমর সৃষ্টি।\r\n✅ ঐতিহাসিক প্রেক্ষাপট: রাসূল ﷺ-এর আগমনের আগে রোম ও পারস্য সাম্রাজ্যের পতন এবং আরবের জাহেলিয়াতের নিখুঁত চিত্র।\r\n✅ আধুনিক জীবনের পাথেয়: চৌদ্দশ বছর আগের আদর্শকে বর্তমান সময়ের প্রেক্ষাপটে কিভাবে প্রয়োগ করা যায়, তার দিকনির্দেশনা।\r\n✅ সহজবোধ্য অনুবাদ: অত্যন্ত সুললিত বাংলা অনুবাদ, যা সর্বস্তরের পাঠকদের জন্য সহজপাঠ্য।💰 অফার মূল্য: মাত্র ৪৯০ টাকা।', 'products/thumbnails/3w5tkvCTfMfnoJFIoKJ4JbZsrlUJkzEwpBFqn0ld.jpg', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 993, 0, 1, '2026-03-26 01:05:29', '2026-03-30 18:51:31'),
(41, 'মুসলিমবঙ্গ', 'muslimbngo-10bY', 'book', 'মুসলিমবঙ্গ', 480.00, NULL, 0.001, NULL, NULL, 0, 'আমরা এক অদ্ভুত সময়ের বাসিন্দা। চেনা পৃথিবী বিদায় নিচ্ছে, আর অনিশ্চিত নতুন ভবিষ্যৎ জন্মযন্ত্রণায় ছটফট করছে।\r\n\r\nপ্রগাঢ় পরিবর্তনের ধাক্কা আছড়ে পড়েছে এই বদ্বীপেও। পরাশক্তিদের রেষারেষি, আঞ্চলিক আধিপত্যবাদ আর অভ্যন্তরীণ অবক্ষয়ের মুখে এই কওম ও যমীনের অস্তিত্ব আজ বিপন্ন।\r\n\r\nএই ক্রান্তিকালে আমাদের নিজস্ব প্রকল্প কী?\r\n\r\nআমরা কি হারিয়ে যাব? অথবা অন্যের উচ্ছিষ্ট খেয়ে তেলাপোকার মতো কোনোমতে বেঁচে থাকাকেই ভাববো সফলতা? নাকি নিজেদের আপন পথ গড়ে নেওয়ার হিম্মত দেখাবো?\r\n\r\nবিদ্যমান ব্যবস্থা মৃত; সমাধান দিতে সে অক্ষম। পুরোনো পথ আর ধার করা পঁচা-গলা তন্ত্রমন্ত্র আমাদের কেবল পরাজয় আর লাঞ্ছনাই উপহার দিয়েছে। বারবার প্রচেষ্টা, রক্তের নাযরানা আর কুরবানির পরও তিন শতাব্দীর অপমানের অধ্যায় শেষ হয়নি।\r\n\r\nঅস্তিত্ব রক্ষার এই লড়াইয়ে বিদ্যমানতার আমূল রূপান্তর অনিবার্য। গোলামির জিঞ্জির ভেঙে, তিন শতকের গ্লানি মুছে মাথা উঁচু করে দাঁড়াবার একটাই পথ: তাওহীদের বুনিয়াদের ওপর এক নতুন সত্তার অভ্যুদয়—মুসলিমবঙ্গ।\r\n\r\nএই বই সেই রূপান্তরের রূপরেখা।\r\n\r\nইতিহাস আমাদের দুয়ারে দাঁড়িয়ে। আমরা কি যুগসন্ধির দায় মেটাতে প্রস্তুত?', 'আমরা এক অদ্ভুত সময়ের বাসিন্দা। চেনা পৃথিবী বিদায় নিচ্ছে, আর অনিশ্চিত নতুন ভবিষ্যৎ জন্মযন্ত্রণায় ছটফট করছে।\r\n\r\nপ্রগাঢ় পরিবর্তনের ধাক্কা আছড়ে পড়েছে এই বদ্বীপেও। পরাশক্তিদের রেষারেষি, আঞ্চলিক আধিপত্যবাদ আর অভ্যন্তরীণ অবক্ষয়ের মুখে এই কওম ও যমীনের অস্তিত্ব আজ বিপন্ন।\r\n\r\nএই ক্রান্তিকালে আমাদের নিজস্ব প্রকল্প কী?\r\n\r\nআমরা কি হারিয়ে যাব? অথবা অন্যের উচ্ছিষ্ট খেয়ে তেলাপোকার মতো কোনোমতে বেঁচে থাকাকেই ভাববো সফলতা? নাকি নিজেদের আপন পথ গড়ে নেওয়ার হিম্মত দেখাবো?\r\n\r\nবিদ্যমান ব্যবস্থা মৃত; সমাধান দিতে সে অক্ষম। পুরোনো পথ আর ধার করা পঁচা-গলা তন্ত্রমন্ত্র আমাদের কেবল পরাজয় আর লাঞ্ছনাই উপহার দিয়েছে। বারবার প্রচেষ্টা, রক্তের নাযরানা আর কুরবানির পরও তিন শতাব্দীর অপমানের অধ্যায় শেষ হয়নি।\r\n\r\nঅস্তিত্ব রক্ষার এই লড়াইয়ে বিদ্যমানতার আমূল রূপান্তর অনিবার্য। গোলামির জিঞ্জির ভেঙে, তিন শতকের গ্লানি মুছে মাথা উঁচু করে দাঁড়াবার একটাই পথ: তাওহীদের বুনিয়াদের ওপর এক নতুন সত্তার অভ্যুদয়—মুসলিমবঙ্গ।\r\n\r\nএই বই সেই রূপান্তরের রূপরেখা।\r\n\r\nইতিহাস আমাদের দুয়ারে দাঁড়িয়ে। আমরা কি যুগসন্ধির দায় মেটাতে প্রস্তুত?', 'products/thumbnails/6qv1edaWCjYsffksUxJLbMU8hwE6Vfga3aqb6FWx.webp', NULL, 440, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1000, 0, 1, '2026-03-26 01:11:09', '2026-03-26 01:11:09'),
